### 🎨 **styles/main.css**

```css
/* Reset e Estilos Globais */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --primary-color: #00ff00;
    --secondary-color: #ff00ff;
    --danger-color: #ff0000;
    --dark-bg: #0a0e27;
    --text-color: #ffffff;
    --accent-color: #00ffff;
}

html, body {
    width: 100%;
    height: 100%;
    background-color: var(--dark-bg);
    color: var(--text-color);
    font-family: 'Courier New', monospace;
    overflow: hidden;
    touch-action: none;
}

.container {
    width: 100%;
    height: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    background: linear-gradient(135deg, #0a0e27 0%, #1a1f4d 100%);
    position: relative;
}

/* Canvas */
#gameCanvas {
    display: block;
    background-color: rgba(10, 14, 39, 0.9);
    border: 3px solid var(--primary-color);
    box-shadow: 0 0 20px rgba(0, 255, 0, 0.3), inset 0 0 20px rgba(0, 255, 0, 0.1);
    image-rendering: pixelated;
    image-rendering: crisp-edges;
    max-width: 100vw;
    max-height: 100vh;
    margin: auto;
}

/* UI Overlay */
.ui-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
}

/* Score Board */
.score-board {
    display: flex;
    justify-content: space-around;
    padding: 20px;
    font-size: 18px;
    font-weight: bold;
    text-shadow: 0 0 10px rgba(0, 255, 0, 0.5);
    color: var(--primary-color);
    z-index: 100;
    pointer-events: none;
}

.score, .lives, .level {
    background: rgba(0, 0, 0, 0.5);
    padding: 8px 15px;
    border: 2px solid var(--primary-color);
    border-radius: 4px;
    box-shadow: 0 0 10px rgba(0, 255, 0, 0.2);
}

.lives span, .score span, .level span {
    color: var(--secondary-color);
    font-weight: bold;
}

/* Menu Styles */
.menu {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(10, 14, 39, 0.95);
    display: flex;
    justify-content: center;
    align-items: center;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s;
    z-index: 1000;
    pointer-events: none;
    backdrop-filter: blur(3px);
}

.menu.active {
    opacity: 1;
    visibility: visible;
    pointer-events: auto;
}

.menu-content {
    text-align: center;
    animation: slideIn 0.5s ease-out;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: translateY(-50px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.title {
    font-size: 4rem;
    font-weight: bold;
    color: var(--primary-color);
    text-shadow: 0 0 20px rgba(0, 255, 0, 0.8), 0 0 40px rgba(255, 0, 255, 0.4);
    margin-bottom: 10px;
    letter-spacing: 3px;
    animation: glow 1.5s ease-in-out infinite;
}

@keyframes glow {
    0%, 100% {
        text-shadow: 0 0 20px rgba(0, 255, 0, 0.8), 0 0 40px rgba(255, 0, 255, 0.4);
    }
    50% {
        text-shadow: 0 0 30px rgba(0, 255, 0, 1), 0 0 60px rgba(255, 0, 255, 0.6);
    }
}

.subtitle {
    font-size: 1.2rem;
    color: var(--accent-color);
    margin-bottom: 40px;
    text-shadow: 0 0 10px rgba(0, 255, 255, 0.5);
}

.menu-content h2 {
    font-size: 2.5rem;
    color: var(--primary-color);
    margin-bottom: 30px;
    text-shadow: 0 0 20px rgba(0, 255, 0, 0.8);
}

.instructions-text {
    max-width: 500px;
    text-align: left;
    margin-bottom: 30px;
    background: rgba(0, 0, 0, 0.5);
    padding: 20px;
    border: 2px solid var(--accent-color);
    border-radius: 8px;
    color: var(--text-color);
    font-size: 0.9rem;
    line-height: 1.8;
}

.instructions-text ul {
    list-style: none;
    margin-left: 20px;
}

.instructions-text li {
    margin: 8px 0;
    color: var(--primary-color);
}

.instructions-text p {
    margin-bottom: 15px;
    color: var(--accent-color);
}

.final-score {
    font-size: 1.5rem;
    color: var(--secondary-color);
    margin-bottom: 30px;
    text-shadow: 0 0 10px rgba(255, 0, 255, 0.5);
}

/* Buttons */
.btn {
    padding: 12px 30px;
    margin: 10px;
    font-size: 1.1rem;
    font-weight: bold;
    border: 2px solid;
    background: transparent;
    cursor: pointer;
    transition: all 0.3s;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-family: 'Courier New', monospace;
}

.btn-primary {
    color: var(--primary-color);
    border-color: var(--primary-color);
    text-shadow: 0 0 5px rgba(0, 255, 0, 0.5);
}

.btn-primary:hover {
    background: rgba(0, 255, 0, 0.1);
    box-shadow: 0 0 20px rgba(0, 255, 0, 0.5), inset 0 0 10px rgba(0, 255, 0, 0.2);
    transform: scale(1.05);
}

.btn-primary:active {
    transform: scale(0.95);
    box-shadow: 0 0 30px rgba(0, 255, 0, 0.8);
}

.btn-secondary {
    color: var(--accent-color);
    border-color: var(--accent-color);
    text-shadow: 0 0 5px rgba(0, 255, 255, 0.5);
}

.btn-secondary:hover {
    background: rgba(0, 255, 255, 0.1);
    box-shadow: 0 0 20px rgba(0, 255, 255, 0.5), inset 0 0 10px rgba(0, 255, 255, 0.2);
    transform: scale(1.05);
}

.btn-secondary:active {
    transform: scale(0.95);
    box-shadow: 0 0 30px rgba(0, 255, 255, 0.8);
}

.credits {
    margin-top: 30px;
    font-size: 0.8rem;
    color: rgba(255, 255, 255, 0.5);
}

/* Mobile Controls */
.mobile-controls {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 80px;
    background: rgba(0, 0, 0, 0.3);
    display: none;
    z-index: 500;
}

@media (max-width: 768px) {
    .mobile-controls {
        display: block;
    }

    .title {
        font-size: 2.5rem;
    }

    .subtitle {
        font-size: 1rem;
    }

    .score-board {
        font-size: 14px;
        padding: 10px;
        gap: 5px;
    }

    .score, .lives, .level {
        padding: 5px 10px;
        font-size: 12px;
    }

    .btn {
        padding: 10px 20px;
        font-size: 0.9rem;
        margin: 8px;
    }

    #gameCanvas {
        width: 100vw;
        height: 100vh;
    }
}

/* Responsividade */
@media (max-width: 480px) {
    .title {
        font-size: 2rem;
    }

    .menu-content h2 {
        font-size: 1.8rem;
    }

    .instructions-text {
        font-size: 0.8rem;
        padding: 15px;
    }

    .score-board {
        flex-direction: column;
        gap: 5px;
    }
}
```

### ⚙️ **js/utils.js**

```javascript
// Utilitários e Helpers
const Utils = {
    // Detecção de dispositivo
    isMobile: () => {
        return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
    },

    // Distância entre dois pontos
    distance: (x1, y1, x2, y2) => {
        const dx = x2 - x1;
        const dy = y2 - y1;
        return Math.sqrt(dx * dx + dy * dy);
    },

    // Detecção de colisão retangular
    rectCollision: (rect1, rect2) => {
        return rect1.x < rect2.x + rect2.width &&
               rect1.x + rect1.width > rect2.x &&
               rect1.y < rect2.y + rect2.height &&
               rect1.y + rect1.height > rect2.y;
    },

    // Detecção de colisão circular
    circleCollision: (circle1, circle2) => {
        const dist = Utils.distance(circle1.x, circle1.y, circle2.x, circle2.y);
        return dist < circle1.radius + circle2.radius;
    },

    // Gerador de números aleatórios
    random: (min, max) => {
        return Math.floor(Math.random() * (max - min + 1)) + min;
    },

    // Clamp (limitar valor entre min e max)
    clamp: (value, min, max) => {
        return Math.min(Math.max(value, min), max);
    },

    // Interpolação linear
    lerp: (start, end, t) => {
        return start + (end - start) * t;
    },

    // Animação de transição
    easeInOutQuad: (t) => {
        return t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;
    },

    // Criar um elemento canvas com desenho
    createCanvasElement: (width, height, drawFn) => {
        const canvas = document.createElement('canvas');
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        drawFn(ctx);
        return canvas;
    }
};

// Gerenciador de Áudio (com fallback se não disponível)
const AudioManager = {
    sounds: {},
    muted: false,

    init: () => {
        // Pode ser expandido para adicionar sons reais
    },

    play: (name) => {
        if (!AudioManager.muted && AudioManager.sounds[name]) {
            try {
                AudioManager.sounds[name].play().catch(e => console.log('Audio play failed:', e));
            } catch (e) {
                console.log('Audio error:', e);
            }
        }
    },

    createSound: (name, frequency = 440, duration = 0.1) => {
        try {
            const audioContext = new (window.AudioContext || window.webkitAudioContext)();
            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();

            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);

            oscillator.frequency.value = frequency;
            oscillator.type = 'square';

            gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
            gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + duration);

            oscillator.start(audioContext.currentTime);
            oscillator.stop(audioContext.currentTime + duration);
        } catch (e) {
            console.log('Audio context not available');
        }
    },

    toggle: () => {
        AudioManager.muted = !AudioManager.muted;
    }
};
