### 🎮 **js/gamestate.js**

```javascript
// Gerenciador de Estado do Jogo
class GameState {
    constructor() {
        this.state = 'menu'; // menu, playing, paused, gameOver, victory
        this.score = 0;
        this.lives = 3;
        this.level = 1;
        this.highScore = this.loadHighScore();
    }

    setState(newState) {
        this.state = newState;
        this.onStateChange(newState);
    }

    onStateChange(newState) {
        const menu = document.getElementById('mainMenu');
        const gameOverMenu = document.getElementById('gameOver');
        const victoryMenu = document.getElementById('victory');
        const pauseMenu = document.getElementById('pauseMenu');
        const instructions = document.getElementById('instructions');

        // Limpar todos os menus
        [menu, gameOverMenu, victoryMenu, pauseMenu, instructions].forEach(el => {
            if (el) el.classList.remove('active');
        });

        // Ativar menu apropriado
        switch (newState) {
            case 'menu':
                if (menu) menu.classList.add('active');
                break;
            case 'gameOver':
                if (gameOverMenu) {
                    gameOverMenu.classList.add('active');
                    document.getElementById('finalScore').textContent = this.score;
                }
                break;
            case 'victory':
                if (victoryMenu) {
                    victoryMenu.classList.add('active');
                    document.getElementById('victoryScore').textContent = this.score;
                }
                break;
            case 'paused':
                if (pauseMenu) pauseMenu.classList.add('active');
                break;
            case 'instructions':
                if (instructions) instructions.classList.add('active');
                break;
        }
    }

    addScore(points) {
        this.score += points;
        if (this.score > this.highScore) {
            this.highScore = this.score;
            this.saveHighScore();
        }
        this.updateUI();
    }

    loseLife() {
        this.lives--;
        this.updateUI();
        return this.lives > 0;
    }

    nextLevel() {
        this.level++;
        this.updateUI();
    }

    updateUI() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('lives').textContent = this.lives;
        document.getElementById('level').textContent = this.level;
    }

    reset() {
        this.score = 0;
        this.lives = 3;
        this.level = 1;
        this.updateUI();
    }

    saveHighScore() {
        localStorage.setItem('galaga-highscore', this.highScore);
    }

    loadHighScore() {
        return parseInt(localStorage.getItem('galaga-highscore') || '0', 10);
    }
}
