### 👾 **js/player.js**

```javascript
// Classe do Jogador
class Player {
    constructor(x, y, width = 30, height = 40) {
        this.x = x;
        this.y = y;
        this.width = width;
        this.height = height;
        this.velocityX = 0;
        this.speed = 6;
        this.isShooting = false;
        this.shootCooldown = 0;
        this.shootRate = 8;
        this.armor = 0;
        this.blinkTime = 0;
    }

    update(canvas, bullets) {
        // Movimento
        this.x += this.velocityX;

        // Limites da tela
        if (this.x < 0) this.x = 0;
        if (this.x + this.width > canvas.width) this.x = canvas.width - this.width;

        // Sistema de tiro
        if (this.isShooting && this.shootCooldown <= 0) {
            this.shoot(bullets);
            this.shootCooldown = this.shootRate;
        }

        if (this.shootCooldown > 0) {
            this.shootCooldown--;
        }

        // Piscar quando invulnerável
        if (this.armor > 0) {
            this.armor--;
            this.blinkTime++;
        }
    }

    shoot(bullets) {
        bullets.push(new Bullet(this.x + this.width / 2 - 2, this.y, 4, 12, 'player'));
        AudioManager.createSound('shoot', 800, 0.05);
    }

    draw(ctx) {
        // Efeito de piscar quando invulnerável
        if (this.armor > 0 && this.blinkTime % 6 < 3) {
            return;
        }

        // Desenho da nave
        ctx.fillStyle = '#00ff00';
        ctx.shadowColor = 'rgba(0, 255, 0, 0.8)';
        ctx.shadowBlur = 10;

        // Corpo da nave
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y); // Ponta
        ctx.lineTo(this.x + this.width, this.y + this.height); // Direita
        ctx.lineTo(this.x + this.width - 8, this.y + this.height - 10); // Motor direito
        ctx.lineTo(this.x + this.width / 2, this.y + this.height - 5); // Centro
        ctx.lineTo(this.x + 8, this.y + this.height - 10); // Motor esquerdo
        ctx.lineTo(this.x, this.y + this.height); // Esquerda
        ctx.closePath();
        ctx.fill();

        // Motores com flama
        ctx.fillStyle = '#ffaa00';
        ctx.fillRect(this.x + 8, this.y + this.height - 8, 6, 8);
        ctx.fillRect(this.x + this.width - 14, this.y + this.height - 8, 6, 8);

        ctx.shadowBlur = 0;
    }

    moveLeft() {
        this.velocityX = -this.speed;
    }

    moveRight() {
        this.velocityX = this.speed;
    }

    stopMove() {
        this.velocityX = 0;
    }

    startShooting() {
        this.isShooting = true;
    }

    stopShooting() {
        this.isShooting = false;
    }

    takeDamage() {
        this.armor = 120; // 2 segundos de invulnerabilidade (120 frames a 60fps)
    }

    getBounds() {
        return {
            x: this.x,
            y: this.y,
            width: this.width,
            height: this.height
        };
    }
}
