// Classe de Projéteis
class Bullet {
    constructor(x, y, width, height, type = 'player', velocityY = -8) {
        this.x = x;
        this.y = y;
        this.width = width;
        this.height = height;
        this.type = type; // 'player' ou 'enemy'
        this.velocityY = velocityY;
        this.active = true;
    }

    update(canvas) {
        this.y += this.velocityY;

        // Remover se sair da tela
        if (this.y < -10 || this.y > canvas.height + 10) {
            this.active = false;
        }
    }

    draw(ctx) {
        ctx.fillStyle = this.type === 'player' ? '#00ff00' : '#ff0000';
        ctx.shadowColor = this.type === 'player' ? 'rgba(0, 255, 0, 0.8)' : 'rgba(255, 0, 0, 0.8)';
        ctx.shadowBlur = 8;

        ctx.fillRect(this.x, this.y, this.width, this.height);

        // Traço do projétil
        ctx.fillStyle = this.type === 'player' ? '#ffff00' : '#ffaa00';
        ctx.fillRect(this.x, this.y + 3, this.width, 2);

        ctx.shadowBlur = 0;
    }

    getBounds() {
        return {
            x: this.x,
            y: this.y,
            width: this.width,
            height: this.height
        };
    }
}

// Gerenciador de Projéteis
class BulletManager {
    constructor() {
        this.playerBullets = [];
        this.enemyBullets = [];
    }

    addPlayerBullet(bullet) {
        this.playerBullets.push(bullet);
    }

    addEnemyBullet(bullet) {
        this.enemyBullets.push(bullet);
    }

    update(canvas) {
        // Atualizar projéteis do jogador
        this.playerBullets.forEach(bullet => bullet.update(canvas));
        this.playerBullets = this.playerBullets.filter(b => b.active);

        // Atualizar projéteis dos inimigos
        this.enemyBullets.forEach(bullet => bullet.update(canvas));
        this.enemyBullets = this.enemyBullets.filter(b => b.active);
    }

    draw(ctx) {
        this.playerBullets.forEach(bullet => bullet.draw(ctx));
        this.enemyBullets.forEach(bullet => bullet.draw(ctx));
    }

    clear() {
        this.playerBullets = [];
        this.enemyBullets = [];
    }
}
