### 👾 **js/enemies.js**

```javascript
// Classe de Inimigo
class Enemy {
    constructor(x, y, type = 'basic') {
        this.x = x;
        this.y = y;
        this.type = type; // 'basic', 'strong', 'boss'
        this.width = type === 'boss' ? 50 : 30;
        this.height = type === 'boss' ? 50 : 30;
        this.health = type === 'basic' ? 1 : type === 'strong' ? 3 : 10;
        this.maxHealth = this.health;
        this.velocityX = 2;
        this.velocityY = 0;
        this.shootCooldown = Utils.random(30, 60);
        this.shootRate = type === 'boss' ? 15 : 40;
        this.points = type === 'basic' ? 10 : type === 'strong' ? 30 : 100;
        this.direction = 1; // 1 ou -1
        this.pattern = 'wave'; // Padrão de movimento
        this.patternCounter = 0;
    }

    update(canvas) {
        // Padrão de movimento
        switch (this.pattern) {
            case 'wave':
                this.x += this.velocityX * this.direction;
                this.y += Math.sin(this.patternCounter * 0.05) * 0.5;
                this.patternCounter++;
                break;
            case 'diagonal':
                this.x += this.velocityX * this.direction;
                this.y += 1;
                break;
            case 'circular':
                this.x += Math.cos(this.patternCounter * 0.05) * 2;
                this.y += Math.sin(this.patternCounter * 0.05) * 2;
                this.patternCounter++;
                break;
        }

        // Limites horizontais
        if (this.x < 0 || this.x + this.width > canvas.width) {
            this.direction *= -1;
            this.y += 20;
        }

        // Remover se sair pela parte inferior
        if (this.y > canvas.height + 50) {
            return false;
        }

        this.shootCooldown--;
        return true;
    }

    shoot(bullets) {
        if (this.shootCooldown <= 0) {
            bullets.push(new Bullet(
                this.x + this.width / 2 - 2,
                this.y + this.height,
                4,
                12,
                'enemy',
                4
            ));
            this.shootCooldown = this.shootRate;
        }
    }

    draw(ctx) {
        const healthPercent = this.health / this.maxHealth;
        const colors = ['#00ff00', '#00ffaa', '#ff00ff'];
        const colorIndex = Math.floor(healthPercent * 2);
        const color = colors[colorIndex];

        ctx.fillStyle = color;
        ctx.shadowColor = `rgba(0, 255, 200, 0.8)`;
        ctx.shadowBlur = 10;

        // Corpo do inimigo
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y);
        ctx.lineTo(this.x + this.width, this.y + this.height / 2);
        ctx.lineTo(this.x + this.width / 2, this.y + this.height);
        ctx.lineTo(this.x, this.y + this.height / 2);
        ctx.closePath();
        ctx.fill();

        // Olhos
        ctx.fillStyle = '#ff0000';
        ctx.fillRect(this.x + 8, this.y + 8, 4, 4);
        ctx.fillRect(this.x + this.width - 12, this.y + 8, 4, 4);

        // Barra de vida para inimigos fortes
        if (this.type === 'strong' || this.type === 'boss') {
            ctx.fillStyle = '#ff0000';
            ctx.fillRect(this.x, this.y - 8, this.width, 4);
            ctx.fillStyle = '#00ff00';
            ctx.fillRect(this.x, this.y - 8, this.width * healthPercent, 4);
        }

        ctx.shadowBlur = 0;
    }

    takeDamage(damage = 1) {
        this.health -= damage;
        return this.health > 0;
    }

    getBounds() {
        return {
            x: this.x,
            y: this.y,
            width: this.width,
            height: this.height
        };
    }
}

// Gerenciador de Inimigos
class EnemyManager {
    constructor(level = 1) {
        this.enemies = [];
        this.level = level;
        this.waveCount = 0;
        this.spawnCooldown = 0;
        this.spawnRate = Math.max(30 - level * 3, 10);
        this.initLevel();
    }

    initLevel() {
        this.waveCount = 0;
        this.enemies = [];
        this.spawnWave();
    }

    spawnWave() {
        const waveSize = 3 + Math.floor(this.level / 2);
        const spacing = 800 / waveSize;

        for (let i = 0; i < waveSize; i++) {
            const type = this.getEnemyType();
            const enemy = new Enemy(50 + i * spacing, -40, type);
            enemy.pattern = this.getPattern();
            this.enemies.push(enemy);
        }

        this.waveCount++;
    }

    getEnemyType() {
        const rand = Math.random();
        if (rand < 0.6) return 'basic';
        if (rand < 0.9) return 'strong';
        return 'boss';
    }

    getPattern() {
        const patterns = ['wave', 'diagonal', 'circular'];
        return patterns[Math.floor(Math.random() * patterns.length)];
    }

    update(canvas) {
        // Atualizar inimigos
        this.enemies = this.enemies.filter(enemy => enemy.update(canvas));

        // Spawnar novos inimigos
        this.spawnCooldown--;
        if (this.spawnCooldown <= 0 && this.waveCount < 5) {
            this.spawnWave();
            this.spawnCooldown = this.spawnRate;
        }
    }

    draw(ctx) {
        this.enemies.forEach(enemy => enemy.draw(ctx));
    }

    allDefeated() {
        return this.enemies.length === 0 && this.waveCount >= 5;
    }

    clear() {
        this.enemies = [];
    }
}
