### 🎮 **js/game.js** (Principal)

```javascript
// Classe Principal do Jogo
class GalagaGame {
    constructor(canvasId) {
        this.canvas = document.getElementById(canvasId);
        this.ctx = this.canvas.getContext('2d');

        // Definir tamanho do canvas
        this.canvas.width = 800;
        this.canvas.height = 600;

        // Inicializar componentes
        this.gameState = new GameState();
        this.player = new Player(this.canvas.width / 2 - 15, this.canvas.height - 60);
        this.bulletManager = new BulletManager();
        this.enemyManager = new EnemyManager(this.gameState.level);
        this.particleManager = new ParticleManager();

        // Controles
        this.keys = {};
        this.touchX = null;
        this.doubleClickTime = 0;

        // Frame rate
        this.fps = 60;
        this.frameTime = 1000 / this.fps;
        this.lastFrameTime = 0;

        // Inicializar eventos
        this.setupEventListeners();
        this.gameState.updateUI();
    }

    setupEventListeners() {
        // Teclado
        document.addEventListener('keydown', (e) => this.handleKeyDown(e));
        document.addEventListener('keyup', (e) => this.handleKeyUp(e));

        // Touch
        document.addEventListener('touchstart', (e) => this.handleTouchStart(e));
        document.addEventListener('touchmove', (e) => this.handleTouchMove(e));
        document.addEventListener('touchend', (e) => this.handleTouchEnd(e));

        // Mouse
        document.addEventListener('click', () => this.handleClick());
        this.canvas.addEventListener('mousemove', (e) => this.handleMouseMove(e));

        // Botões UI
        document.getElementById('startBtn').addEventListener('click', () => this.start());
        document.getElementById('instructionsBtn').addEventListener('click', () => {
            this.gameState.setState('instructions');
        });
        document.getElementById('backBtn').addEventListener('click', () => {
            this.gameState.setState('menu');
        });
        document.getElementById('resumeBtn').addEventListener('click', () => {
            this.gameState.setState('playing');
        });
        document.getElementById('restartBtn').addEventListener('click', () => this.restart());
        document.getElementById('nextBtn').addEventListener('click', () => this.nextLevel());

        // Menu botões
        [
            { id: 'menuBtn', action: () => this.gameState.setState('menu') },
            { id: 'menuBtn2', action: () => this.gameState.setState('menu') },
            { id: 'menuBtn3', action: () => this.gameState.setState('menu') }
        ].forEach(btn => {
            const el = document.getElementById(btn.id);
            if (el) el.addEventListener('click', btn.action);
        });
    }

    handleKeyDown(e) {
        this.keys[e.key.toLowerCase()] = true;

        if (e.key === 'ArrowLeft') {
            this.player.moveLeft();
        } else if (e.key === 'ArrowRight') {
            this.player.moveRight();
        } else if (e.key === ' ') {
            e.preventDefault();
            this.player.startShooting();
        } else if (e.key === 'p' || e.key === 'P') {
            if (this.gameState.state === 'playing') {
                this.gameState.setState('paused');
            } else if (this.gameState.state === 'paused') {
                this.gameState.setState('playing');
            }
        }
    }

    handleKeyUp(e) {
        this.keys[e.key.toLowerCase()] = false;

        if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
            this.player.stopMove();
        } else if (e.key === ' ') {
            this.player.stopShooting();
        }
    }

    handleTouchStart(e) {
        if (this.gameState.state === 'playing') {
            e.preventDefault();
            this.touchX = e.touches[0].clientX;
            this.doubleClickTime++;

            if (this.doubleClickTime >= 2) {
                this.player.startShooting();
                this.doubleClickTime = 0;
            }

            setTimeout(() => {
                this.doubleClickTime = 0;
            }, 300);
        }
    }

    handleTouchMove(e) {
        if (this.gameState.state === 'playing' && this.touchX !== null) {
            e.preventDefault();
            const touch = e.touches[0];
            const deltaX = touch.clientX - this.touchX;

            if (deltaX < -10) {
                this.player.moveLeft();
            } else if (deltaX > 10) {
                this.player.moveRight();
            } else {
                this.player.stopMove();
            }
        }
    }

    handleTouchEnd(e) {
        if (this.gameState.state === 'playing') {
            this.player.stopMove();
            this.player.stopShooting();
            this.touchX = null;
        }
    }

    handleMouseMove(e) {
        if (this.gameState.state === 'playing' && Utils.isMobile() === false) {
            const rect = this.canvas.getBoundingClientRect();
            const mouseX = e.clientX - rect.left;

            if (mouseX < this.player.x) {
                this.player.moveLeft();
            } else if (mouseX > this.player.x + this.player.width) {
                this.player.moveRight();
            } else {
                this.player.stopMove();
            }
        }
    }

    handleClick() {
        if (this.gameState.state === 'playing' && Utils.isMobile() === false) {
            this.player.startShooting();
        }
    }

    start() {
        this.gameState.reset();
        this.gameState.setState('playing');
        this.enemyManager = new EnemyManager(this.gameState.level);
        this.bulletManager.clear();
        this.particleManager.clear();
        this.animate(0);
    }

    restart() {
        this.start();
    }

    nextLevel() {
        this.gameState.nextLevel();
        this.start();
    }

    update() {
        if (this.gameState.state !== 'playing') return;

        // Atualizar jogador
        this.player.update(this.canvas, this.bulletManager.playerBullets);

        // Atualizar projéteis
        this.bulletManager.update(this.canvas);

        // Atualizar inimigos
        this.enemyManager.update(this.canvas);

        // Inimigos atirando
        this.enemyManager.enemies.forEach(enemy => {
            enemy.shoot(this.bulletManager.enemyBullets);
        });

        // Atualizar partículas
        this.particleManager.update();

        // Colisão: projéteis do jogador com inimigos
        this.bulletManager.playerBullets.forEach((bullet, bulletIndex) => {
            this.enemyManager.enemies.forEach((enemy, enemyIndex) => {
                if (Utils.rectCollision(bullet.getBounds(), enemy.getBounds())) {
                    bullet.active = false;

                    if (!enemy.takeDamage()) {
                        this.particleManager.createExplosion(
                            enemy.x + enemy.width / 2,
                            enemy.y + enemy.height / 2,
                            15,
                            '#ff00ff'
                        );
                        this.enemyManager.enemies.splice(enemyIndex, 1);
                        this.gameState.addScore(enemy.points);
                        AudioManager.createSound('explosion', 200, 0.1);
                    } else {
                        AudioManager.createSound('hit', 600, 0.05);
                    }
                }
            });
        });

        // Colisão: projéteis dos inimigos com jogador
        this.bulletManager.enemyBullets.forEach((bullet, bulletIndex) => {
            if (Utils.rectCollision(bullet.getBounds(), this.player.getBounds())) {
                if (this.player.armor <= 0) {
                    bullet.active = false;
                    this.player.takeDamage();
                    this.particleManager.createExplosion(
                        this.player.x + this.player.width / 2,
                        this.player.y,
                        10,
                        '#ff0000'
                    );

                    if (!this.gameState.loseLife()) {
                        this.gameState.setState('gameOver');
                    }
                    AudioManager.createSound('damage', 100, 0.2);
                }
            }
        });

        // Colisão: inimigos tocando o jogador
        this.enemyManager.enemies.forEach(enemy => {
            if (Utils.rectCollision(enemy.getBounds(), this.player.getBounds())) {
                if (this.player.armor <= 0) {
                    this.player.takeDamage();
                    this.particleManager.createExplosion(
                        this.player.x + this.player.width / 2,
                        this.player.y,
                        10,
                        '#ff0000'
                    );

                    if (!this.gameState.loseLife()) {
                        this.gameState.setState('gameOver');
                    }
                }
            }
        });

        // Verificar vitória
        if (this.enemyManager.allDefeated()) {
            this.gameState.setState('victory');
        }

        // Inimigos descendo
        this.enemyManager.enemies.forEach(enemy => {
            if (enemy.y > this.canvas.height) {
                this.gameState.setState('gameOver');
            }
        });
    }

    draw() {
        // Fundo
        this.ctx.fillStyle = '#0a0e27';
        this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

        // Grade (efeito retrô)
        this.drawGrid();

        if (this.gameState.state === 'playing' || this.gameState.state === 'paused') {
            // Desenhar ativos
            this.enemyManager.draw(this.ctx);
            this.bulletManager.draw(this.ctx);
            this.player.draw(this.ctx);
            this.particleManager.draw(this.ctx);

            // Desenhar informações
            this.drawGameInfo();
        }
    }

    drawGrid() {
        this.ctx.strokeStyle = 'rgba(0, 255, 0, 0.03)';
        this.ctx.lineWidth = 1;

        for (let x = 0; x < this.canvas.width; x += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(x, 0);
            this.ctx.lineTo(x, this.canvas.height);
            this.ctx.stroke();
        }

        for (let y = 0; y < this.canvas.height; y += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, y);
            this.ctx.lineTo(this.canvas.width, y);
            this.ctx.stroke();
        }
    }

    drawGameInfo() {
        if (this.gameState.state === 'paused') {
            this.ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
            this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
        }
    }

    animate(currentTime) {
        if (currentTime - this.lastFrameTime >= this.frameTime) {
            this.update();
            this.draw();
            this.lastFrameTime = currentTime;
        }

        requestAnimationFrame((time) => this.animate(time));
    }
}

