   GALAGA ARCADE - Estilos
   =========================== */

:root {
    --color-bg: #000000;
    --color-text: #00ff00;
    --color-text-alt: #ffff00;
    --color-player: #00ff00;
    --color-enemy: #ff00ff;
    --color-enemy-strong: #ff0080;
    --color-boss: #ff6600;
    --color-bullet: #ffff00;
    --color-enemy-bullet: #ff0000;
    --color-particle: #00ffff;
    --color-border: #0099ff;
    --font-arcade: 'Press Start 2P', cursive;
    --shadow-glow: 0 0 20px rgba(0, 255, 0, 0.8);
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html, body {
    width: 100%;
    height: 100%;
    background: var(--color-bg);
    color: var(--color-text);
    font-family: var(--font-arcade);
    overflow: hidden;
    user-select: none;
    -webkit-user-select: none;
    -webkit-touch-callout: none;
}

body {
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    width: 100%;
    max-width: 900px;
    padding: 10px;
    display: flex;
    flex-direction: column;
    gap: 10px;
}

/* ===========================
   HEADER & SCOREBOARD
   =========================== */

.header {
    text-align: center;
    border: 3px solid var(--color-border);
    background: linear-gradient(135deg, rgba(0, 153, 255, 0.2), rgba(0, 255, 0, 0.1));
    padding: 15px;
    box-shadow: var(--shadow-glow), inset 0 0 10px rgba(0, 255, 0, 0.3);
}

.title {
    font-size: 28px;
    color: var(--color-text-alt);
    text-shadow: 0 0 10px var(--color-text-alt), 0 0 20px rgba(255, 255, 0, 0.5);
    margin-bottom: 10px;
    letter-spacing: 2px;
    animation: pulse 2s infinite;
}

@keyframes pulse {
    0%, 100% {
        text-shadow: 0 0 10px var(--color-text-alt);
    }
    50% {
        text-shadow: 0 0 20px var(--color-text-alt), 0 0 30px rgba(255, 255, 0, 0.8);
    }
}

.score-board {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 15px;
    margin-top: 10px;
}

.score-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 5px;
    padding: 10px;
    border: 2px solid var(--color-border);
    background: rgba(0, 99, 153, 0.3);
    border-radius: 5px;
}

.score-item .label {
    font-size: 10px;
    color: var(--color-text);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.score-item .value {
    font-size: 14px;
    color: var(--color-text-alt);
    text-shadow: 0 0 10px var(--color-text-alt);
}

/* ===========================
   GAME CANVAS
   =========================== */

.game-wrapper {
    width: 100%;
    max-width: 800px;
    margin: 0 auto;
    border: 4px solid var(--color-border);
    box-shadow: 0 0 30px rgba(0, 255, 0, 0.6), inset 0 0 20px rgba(0, 0, 0, 0.8);
    background: var(--color-bg);
    aspect-ratio: 4/3;
}

#gameCanvas {
    width: 100%;
    height: 100%;
    display: block;
    background: var(--color-bg);
}

/* ===========================
   STATUS BAR
   =========================== */

.status-bar {
    text-align: center;
    padding: 8px;
    background: rgba(0, 0, 0, 0.7);
    border: 2px solid var(--color-border);
    color: var(--color-text);
    font-size: 12px;
    min-height: 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 0 10px rgba(0, 255, 0, 0.3);
}

/* ===========================
   CONTROLS INFO
   =========================== */

.controls {
    font-size: 10px;
    color: var(--color-text);
    text-align: center;
    gap: 10px;
    display: flex;
    flex-direction: column;
}

.controls p {
    margin: 5px 0;
    padding: 8px;
    background: rgba(0, 0, 0, 0.5);
    border: 1px solid var(--color-border);
    border-radius: 3px;
}

.controls-mobile {
    display: none;
}

/* ===========================
   MODAL (Pause/GameOver)
   =========================== */

.modal {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.9);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
    border: 2px solid var(--color-text-alt);
}

.modal.hidden {
    display: none;
}

.modal-content {
    background: linear-gradient(135deg, rgba(0, 0, 0, 0.95), rgba(0, 50, 100, 0.8));
    border: 4px solid var(--color-text-alt);
    padding: 40px;
    text-align: center;
    border-radius: 10px;
    box-shadow: 0 0 50px var(--color-text-alt), inset 0 0 30px rgba(0, 255, 0, 0.3);
    animation: scaleIn 0.3s ease-out;
}

@keyframes scaleIn {
    from {
        transform: scale(0.5);
        opacity: 0;
    }
    to {
        transform: scale(1);
        opacity: 1;
    }
}

.modal-content h2 {
    font-size: 32px;
    color: var(--color-text-alt);
    margin-bottom: 20px;
    text-shadow: 0 0 20px var(--color-text-alt);
}

.modal-content p {
    font-size: 14px;
    color: var(--color-text);
    margin: 10px 0;
}

.modal-content #newRecord {
    color: var(--color-text-alt);
    font-size: 16px;
    animation: blink 0.5s infinite;
}

@keyframes blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
}

#newRecord.hidden {
    display: none;
}

/* ===========================
   BUTTONS
   =========================== */

.btn {
    margin-top: 20px;
    padding: 12px 24px;
    font-size: 12px;
    font-family: var(--font-arcade);
    background: linear-gradient(135deg, var(--color-text-alt), #ffcc00);
    color: #000;
    border: 2px solid var(--color-text-alt);
    cursor: pointer;
    border-radius: 5px;
    transition: all 0.2s;
    box-shadow: 0 0 10px rgba(255, 255, 0, 0.5);
}

.btn:hover {
    transform: scale(1.05);
    box-shadow: 0 0 20px rgba(255, 255, 0, 0.8);
}

.btn:active {
    transform: scale(0.95);
}

/* ===========================
   TOUCH CONTROLS
   =========================== */

.touch-controls {
    display: none;
    position: fixed;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 120px;
    background: rgba(0, 0, 0, 0.8);
    border-top: 2px solid var(--color-border);
    z-index: 100;
}

.touch-controls.visible {
    display: flex;
}

.touch-pad {
    display: flex;
    width: 100%;
    height: 100%;
    gap: 2px;
    padding: 5px;
}

.touch-zone {
    flex: 1;
    border: 2px solid var(--color-border);
    background: rgba(0, 255, 0, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 12px;
    color: var(--color-text);
    cursor: pointer;
    user-select: none;
    -webkit-user-select: none;
    transition: background 0.1s;
}

.touch-zone:active {
    background: rgba(0, 255, 0, 0.3);
    box-shadow: inset 0 0 10px rgba(0, 255, 0, 0.5);
}

.touch-zone.left::before {
    content: "◄";
}

.touch-zone.right::before {
    content: "►";
}

.touch-zone.shoot::before {
    content: "ATIRAR";
    font-size: 14px;
}

/* ===========================
   RESPONSIVE DESIGN
   =========================== */

/* Tablets */
@media (max-width: 768px) {
    .header {
        padding: 10px;
    }

    .title {
        font-size: 20px;
    }

    .score-board {
        grid-template-columns: repeat(2, 1fr);
        gap: 10px;
    }

    .score-item .label {
        font-size: 8px;
    }

    .score-item .value {
        font-size: 12px;
    }

    .controls p {
        font-size: 9px;
    }

    .game-wrapper {
        max-width: 100%;
    }
}

