{"owner": "wegah", "repo": "galaga-arcade", "branch": "main", "message": "Add JavaScript game engine and modules", "files": [{"path":"js/utils.js","content":"/**
 * GALAGA ARCADE - Utilitários
 * Funções auxiliares e classes base
 */

// ===========================
// UTILIDADES GERAIS
// ===========================

/**
 * Gera um número aleatório entre min e max
 */
function random(min, max) {
    return Math.random() * (max - min) + min;
}

/**
 * Gera um número inteiro aleatório entre min e max
 */
function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Detecta colisão entre dois retângulos
 */
function checkCollision(rect1, rect2) {
    return rect1.x < rect2.x + rect2.width &&
           rect1.x + rect1.width > rect2.x &&
           rect1.y < rect2.y + rect2.height &&
           rect1.y + rect1.height > rect2.y;
}

/**
 * Detecta colisão entre círculo e retângulo
 */
function checkCircleRectCollision(circle, rect) {
    const closestX = Math.max(rect.x, Math.min(circle.x, rect.x + rect.width));
    const closestY = Math.max(rect.y, Math.min(circle.y, rect.y + rect.height));

    const distX = circle.x - closestX;
    const distY = circle.y - closestY;

    return (distX * distX + distY * distY) < (circle.radius * circle.radius);
}

/**
 * Limita um valor entre min e max
 */
function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
}

/**
 * Interpola linearmente entre dois valores
 */
function lerp(a, b, t) {
    return a + (b - a) * t;
}

/**
 * Calcula distância entre dois pontos
 */
function distance(x1, y1, x2, y2) {
    const dx = x2 - x1;
    const dy = y2 - y1;
    return Math.sqrt(dx * dx + dy * dy);
}

/**
 * Calcula ângulo entre dois pontos (em radianos)
 */
function getAngle(x1, y1, x2, y2) {
    return Math.atan2(y2 - y1, x2 - x1);
}

/**
 * Converte graus para radianos
 */
function degToRad(deg) {
    return deg * (Math.PI / 180);
}

/**
 * Converte radianos para graus
 */
function radToDeg(rad) {
    return rad * (180 / Math.PI);
}

// ===========================
// DETECÇÃO DE DISPOSITIVO
// ===========================

/**
 * Detecta se é um dispositivo móvel
 */
function isMobileDevice() {
    return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
}

/**
 * Detecta se tem suporte a touch
 */
function isTouchDevice() {
    return (
        (typeof window !== 'undefined' &&
            ('ontouchstart' in window ||
             navigator.maxTouchPoints > 0 ||
             navigator.msMaxTouchPoints > 0))
    );
}

// ===========================
// MANIPULAÇÃO DE DOM
// ===========================

/**
 * Obtém elemento por ID com segurança
 */
function getElement(id) {
    return document.getElementById(id);
}

/**
 * Define classe CSS com toggle
 */
function toggleClass(element, className) {
    if (element) {
        element.classList.toggle(className);
    }
}

/**
 * Adiciona classe CSS
 */
function addClass(element, className) {
    if (element) {
        element.classList.add(className);
    }
}

/**
 * Remove classe CSS
 */
function removeClass(element, className) {
    if (element) {
        element.classList.remove(className);
    }
}

/**
 * Verifica se elemento tem classe
 */
function hasClass(element, className) {
    return element && element.classList.contains(className);
}

/**
 * Define texto do elemento
 */
function setText(id, text) {
    const element = getElement(id);
    if (element) {
        element.textContent = text;
    }
}

/**
 * Atualiza texto formatado com número
 */
function updateScore(id, value) {
    setText(id, String(value).padStart(6, '0'));
}

// ===========================
// ARMAZENAMENTO LOCAL
// ===========================

/**
 * Obtém valor do localStorage
 */
function getLocalStorage(key, defaultValue = null) {
    try {
        const value = localStorage.getItem(key);
        return value ? JSON.parse(value) : defaultValue;
    } catch (e) {
        console.warn('localStorage read error:', e);
        return defaultValue;
    }
}

/**
 * Define valor no localStorage
 */
function setLocalStorage(key, value) {
    try {
        localStorage.setItem(key, JSON.stringify(value));
        return true;
    } catch (e) {
        console.warn('localStorage write error:', e);
        return false;
    }
}

/**
 * Remove valor do localStorage
 */
function removeLocalStorage(key) {
    try {
        localStorage.removeItem(key);
        return true;
    } catch (e) {
        console.warn('localStorage remove error:', e);
        return false;
    }
}

// ===========================
// CLASSE BASE - GAMEOBJECT
// ===========================

/**
 * Classe base para todos os objetos do jogo
 */
class GameObject {
    constructor(x = 0, y = 0, width = 10, height = 10) {
        this.x = x;
        this.y = y;
        this.width = width;
        this.height = height;
        this.vx = 0;
        this.vy = 0;
        this.active = true;
    }

    /**
     * Atualiza a posição
     */
    update() {
        this.x += this.vx;
        this.y += this.vy;
    }

    /**
     * Desenha o objeto
     */
    draw(ctx) {
        ctx.fillStyle = '#fff';
        ctx.fillRect(this.x, this.y, this.width, this.height);
    }

    /**
     * Verifica se está fora da tela
     */
    isOutOfBounds(canvasWidth, canvasHeight, margin = 50) {
        return this.x + this.width < -margin ||
               this.x > canvasWidth + margin ||
               this.y + this.height < -margin ||
               this.y > canvasHeight + margin;
    }

    /**
     * Retorna rect para detecção de colisão
     */
    getRect() {
        return {
            x: this.x,
            y: this.y,
            width: this.width,
            height: this.height
        };
    }
}

// ===========================
// PERFORMANCE & DEBUG
// ===========================

/**
 * Conta frames por segundo
 */
class FPSCounter {
    constructor() {
        this.fps = 0;
        this.frameCount = 0;
        this.lastTime = Date.now();
    }

    update() {
        this.frameCount++;
        const currentTime = Date.now();
        const elapsed = currentTime - this.lastTime;

        if (elapsed >= 1000) {
            this.fps = this.frameCount;
            this.frameCount = 0;
            this.lastTime = currentTime;
        }

        return this.fps;
    }
}

// ===========================
// TIMER
// ===========================

/**
 * Timer simples
 */
class Timer {
    constructor(duration = 1000) {
        this.duration = duration;
        this.elapsed = 0;
        this.active = false;
    }

    start() {
        this.active = true;
        this.elapsed = 0;
    }

    stop() {
        this.active = false;
    }

    update(deltaTime = 16) {
        if (this.active) {
            this.elapsed += deltaTime;
            if (this.elapsed >= this.duration) {
                this.active = false;
                return true;
            }
        }
        return false;
    }

    getProgress() {
        return Math.min(1, this.elapsed / this.duration);
    }

    isFinished() {
        return !this.active && this.elapsed >= this.duration;
    }
}
