 * GALAGA ARCADE - Gerenciador de Estado
 * Controla os diferentes estados do jogo
 */

const GameStates = {
    MENU: 'menu',
    PLAYING: 'playing',
    PAUSED: 'paused',
    LEVEL_UP: 'levelup',
    GAME_OVER: 'gameover'
};

/**
 * Classe para gerenciar o estado do jogo
 */
class GameStateManager {
    constructor() {
        this.currentState = GameStates.MENU;
        this.previousState = null;
        this.score = 0;
        this.highScore = this.loadHighScore();
        this.level = 1;
        this.lives = 3;
        this.isNewRecord = false;
    }

    /**
     * Muda para novo estado
     */
    setState(newState) {
        this.previousState = this.currentState;
        this.currentState = newState;
    }

    /**
     * Verifica se está em determinado estado
     */
    isState(state) {
        return this.currentState === state;
    }

    /**
     * Adiciona pontos
     */
    addScore(points) {
        this.score += points;
        if (this.score > this.highScore) {
            this.highScore = this.score;
            this.isNewRecord = true;
            this.saveHighScore();
        }
    }

    /**
     * Reseta para novo jogo
     */
    reset() {
        this.score = 0;
        this.level = 1;
        this.lives = 3;
        this.isNewRecord = false;
        this.setState(GameStates.PLAYING);
    }

    /**
     * Próximo nível
     */
    nextLevel() {
        this.level++;
        this.setState(GameStates.LEVEL_UP);
    }

    /**
     * Perde uma vida
     */
    loseLife() {
        this.lives--;
        if (this.lives <= 0) {
            this.setState(GameStates.GAME_OVER);
            return false;
        }
        return true;
    }

    /**
     * Salva high score no localStorage
     */
    saveHighScore() {
        setLocalStorage('galaga_highscore', this.highScore);
    }

    /**
     * Carrega high score do localStorage
     */
    loadHighScore() {
        return getLocalStorage('galaga_highscore', 0);
    }

    /**
     * Retorna progresso para próximo level
     */
    getLevelProgress() {
        const maxLevel = 10;
        return Math.min(1, this.level / maxLevel);
    }

    /**
     * Retorna multiplicador de dificuldade
     */
    getDifficultyMultiplier() {
        return 1 + (this.level - 1) * 0.2;
    }
}
"},{"path":"js/audio.js","content":"/**
 * GALAGA ARCADE - Sistema de Áudio
 * Gerencia efeitos sonoros e música
 */

/**
 * Gerenciador de áudio com Web Audio API
 */
class AudioManager {
    constructor() {
        this.audioContext = null;
        this.masterVolume = 0.3;
        this.soundEnabled = true;
        this.musicEnabled = true;
        this.initAudioContext();
    }

    /**
     * Inicializa contexto de áudio
     */
    initAudioContext() {
        try {
            const AudioContext = window.AudioContext || window.webkitAudioContext;
            if (AudioContext) {
                this.audioContext = new AudioContext();
            }
        } catch (e) {
            console.warn('Web Audio API não disponível:', e);
        }
    }

    /**
     * Certifica que o contexto de áudio está rodando
     */
    resumeAudioContext() {
        if (this.audioContext && this.audioContext.state === 'suspended') {
            this.audioContext.resume();
        }
    }

    /**
     * Toca som de tiro
     */
    playShoot() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playTone(400, 0.1, 0.05);
    }

    /**
     * Toca som de explosão
     */
    playExplosion() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playNoise(200, 0.3);
    }

    /**
     * Toca som de game over
     */
    playGameOver() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playTone(200, 0.3, 0.5);
    }

    /**
     * Toca som de nível completo
     */
    playLevelUp() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playTone(800, 0.2, 0.1);
    }

    /**
     * Toca tom de frequência específica
     */
    playTone(frequency, volume = 0.3, duration = 0.1) {
        if (!this.audioContext) return;

        try {
            const now = this.audioContext.currentTime;
            const osc = this.audioContext.createOscillator();
            const gain = this.audioContext.createGain();

            osc.connect(gain);
            gain.connect(this.audioContext.destination);

            osc.frequency.value = frequency;
            gain.gain.setValueAtTime(volume * this.masterVolume, now);
            gain.gain.exponentialRampToValueAtTime(0.01, now + duration);

            osc.start(now);
            osc.stop(now + duration);
        } catch (e) {
            console.warn('Erro ao tocar tom:', e);
        }
    }

    /**
     * Toca ruído
     */
    playNoise(duration = 0.2, volume = 0.3) {
        if (!this.audioContext) return;

        try {
            const now = this.audioContext.currentTime;
            const bufferSize = this.audioContext.sampleRate * duration;
            const buffer = this.audioContext.createBuffer(1, bufferSize, this.audioContext.sampleRate);
            const data = buffer.getChannelData(0);

            for (let i = 0; i < bufferSize; i++) {
                data[i] = Math.random() * 2 - 1;
            }

            const source = this.audioContext.createBufferSource();
            const gain = this.audioContext.createGain();

            source.buffer = buffer;
            source.connect(gain);
            gain.connect(this.audioContext.destination);

            gain.gain.setValueAtTime(volume * this.masterVolume, now);
            gain.gain.exponentialRampToValueAtTime(0.01, now + duration);

            source.start(now);
        } catch (e) {
            console.warn('Erro ao tocar ruído:', e);
        }
    }

    /**
     * Define volume mestre
     */
    setMasterVolume(volume) {
        this.masterVolume = clamp(volume, 0, 1);
    }

    /**
     * Alterna sons
     */
    toggleSound() {
        this.soundEnabled = !this.soundEnabled;
        return this.soundEnabled;
    }

    /**
     * Alterna música
     */
    toggleMusic() {
        this.musicEnabled = !this.musicEnabled;
        return this.musicEnabled;
    }
}

// Instância global do gerenciador de áudio
let audioManager = null;

/**
 * Inicializa o gerenciador de áudio
 */
function initAudio() {
    audioManager = new AudioManager();
    return audioManager;
}

/**
 * Obtém a instância do gerenciador de áudio
 */
function getAudioManager() {
    if (!audioManager) {
        audioManager = new AudioManager();
    }
    return audioManager;
}
"},{"path":"js/player.js","content":"/**
 * GALAGA ARCADE - Jogador
 * Controla a nave do jogador
 */

class Player extends GameObject {
    constructor(x, y) {
        super(x, y, 20, 25);
        this.speed = 5;
        this.canShoot = true;
        this.shootCooldown = 0;
        this.maxHealth = 1;
        this.health = this.maxHealth;
        this.invincible = false;
        this.invincibilityDuration = 120; // frames
        this.invincibilityCounter = 0;
    }

    /**
     * Atualiza o jogador
     */
    update(keys, canvas) {
        // Movimento horizontal
        if (keys['ArrowLeft'] || keys['a']) {
            this.vx = -this.speed;
        } else if (keys['ArrowRight'] || keys['d']) {
            this.vx = this.speed;
        } else {
            this.vx = 0;
        }

        // Atualiza posição
        this.x += this.vx;

        // Limita ao canvas
        if (this.x < 0) this.x = 0;
        if (this.x + this.width > canvas.width) {
            this.x = canvas.width - this.width;
        }

        // Atualiza invencibilidade
        if (this.invincible) {
            this.invincibilityCounter++;
            if (this.invincibilityCounter >= this.invincibilityDuration) {
                this.invincible = false;
                this.invincibilityCounter = 0;
            }
        }

        // Atualiza cooldown de tiro
        if (this.shootCooldown > 0) {
            this.shootCooldown--;
        } else {
            this.canShoot = true;
        }
    }

    /**
     * Atira um projétil
     */
    shoot() {
        if (this.canShoot && this.shootCooldown <= 0) {
            this.shootCooldown = 8;
            this.canShoot = false;

            // Reproduz som de tiro
            if (audioManager) {
                audioManager.playShoot();
            }

            return new Bullet(
                this.x + this.width / 2 - 2,
                this.y,
                0,
                -7,
                true
            );
        }
        return null;
    }

    /**
     * Toma dano
     */
    takeDamage(amount = 1) {
        if (this.invincible) return;

        this.health -= amount;
        this.invincible = true;
        this.invincibilityCounter = 0;

        if (audioManager) {
            audioManager.playExplosion();
        }

        return this.health <= 0;
    }

    /**
     * Cura o jogador
     */
    heal(amount = 1) {
        this.health = Math.min(this.maxHealth, this.health + amount);
    }

    /**
     * Desenha o jogador
     */
    draw(ctx) {
        // Pisca se estiver invencível
        if (this.invincible && Math.floor(this.invincibilityCounter / 5) % 2 === 0) {
            return;
        }

        // Desenha nave
        ctx.fillStyle = '#00ff00';
        ctx.shadowColor = 'rgba(0, 255, 0, 0.8)';
        ctx.shadowBlur = 10;

        // Corpo da nave
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y);
        ctx.lineTo(this.x + this.width, this.y + this.height);
        ctx.lineTo(this.x + this.width - 5, this.y + this.height);
        ctx.lineTo(this.x + this.width / 2 + 3, this.y + 10);
        ctx.lineTo(this.x + this.width / 2 - 3, this.y + 10);
        ctx.lineTo(this.x + 5, this.y + this.height);
        ctx.lineTo(this.x, this.y + this.height);
        ctx.closePath();
        ctx.fill();

        // Visor
        ctx.fillStyle = '#ffff00';
        ctx.fillRect(this.x + this.width / 2 - 3, this.y + 5, 6, 3);

        ctx.shadowColor = 'transparent';
    }

    /**
     * Reseta o jogador
     */
    reset(x, y) {
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
        this.health = this.maxHealth;
        this.invincible = true;
        this.invincibilityCounter = 0;
    }
}
"},{"path":"js/bullets.js","content":"/**
 * GALAGA ARCADE - Sistema de Projéteis
 * Gerencia projéteis do jogador e inimigos
 */

/**
 * Classe para projéteis
 */
class Bullet extends GameObject {
    constructor(x, y, vx, vy, isPlayerBullet = false) {
        super(x, y, 4, 10);
        this.vx = vx;
        this.vy = vy;
        this.isPlayerBullet = isPlayerBullet;
        this.damage = 1;
    }

    /**
     * Atualiza projétil
     */
    update() {
        this.x += this.vx;
        this.y += this.vy;
    }

    /**
     * Desenha projétil
     */
    draw(ctx) {
        if (this.isPlayerBullet) {
            ctx.fillStyle = '#ffff00';
            ctx.shadowColor = 'rgba(255, 255, 0, 0.8)';
        } else {
            ctx.fillStyle = '#ff0000';
            ctx.shadowColor = 'rgba(255, 0, 0, 0.6)';
        }
        ctx.shadowBlur = 5;
        ctx.fillRect(this.x, this.y, this.width, this.height);
        ctx.shadowColor = 'transparent';
    }
}

/**
 * Gerenciador de projéteis
 */
class BulletManager {
    constructor() {
        this.playerBullets = [];
        this.enemyBullets = [];
    }

    /**
     * Adiciona projétil do jogador
     */
    addPlayerBullet(bullet) {
        if (bullet) {
            this.playerBullets.push(bullet);
        }
    }

    /**
     * Adiciona projétil do inimigo
     */
    addEnemyBullet(bullet) {
        if (bullet) {
            this.enemyBullets.push(bullet);
        }
    }

    /**
     * Atualiza todos os projéteis
     */
    update(canvasWidth, canvasHeight) {
        // Atualiza projéteis do jogador
        for (let i = this.playerBullets.length - 1; i >= 0; i--) {
            const bullet = this.playerBullets[i];
            bullet.update();

            if (bullet.isOutOfBounds(canvasWidth, canvasHeight, 10)) {
                this.playerBullets.splice(i, 1);
            }
        }

        // Atualiza projéteis do inimigo
        for (let i = this.enemyBullets.length - 1; i >= 0; i--) {
            const bullet = this.enemyBullets[i];
            bullet.update();

            if (bullet.isOutOfBounds(canvasWidth, canvasHeight, 10)) {
                this.enemyBullets.splice(i, 1);
            }
        }
    }

    /**
     * Desenha todos os projéteis
     */
    draw(ctx) {
        this.playerBullets.forEach(bullet => bullet.draw(ctx));
        this.enemyBullets.forEach(bullet => bullet.draw(ctx));
    }

    /**
     * Remove todos os projéteis
     */
    clear() {
        this.playerBullets = [];
        this.enemyBullets = [];
    }

    /**
     * Remove projétil específico
     */
    removeBullet(bullet) {
        const pIndex = this.playerBullets.indexOf(bullet);
        if (pIndex > -1) {
            this.playerBullets.splice(pIndex, 1);
        }
        const eIndex = this.enemyBullets.indexOf(bullet);
        if (eIndex > -1) {
            this.enemyBullets.splice(eIndex, 1);
        }
    }
}
"},{"path":"js/particles.js","content":"/**
 * GALAGA ARCADE - Sistema de Partículas
 * Efeitos visuais de explosões e impactos
 */

/**
 * Classe para partícula individual
 */
class Particle extends GameObject {
    constructor(x, y, vx, vy, lifetime = 30, size = 3) {
        super(x, y, size, size);
        this.vx = vx;
        this.vy = vy;
        this.lifetime = lifetime;
        this.maxLifetime = lifetime;
        this.gravity = 0.1;
        this.color = '#00ffff';
        this.opacity = 1;
    }

    /**
     * Atualiza partícula
     */
    update() {
        this.x += this.vx;
        this.y += this.vy;
        this.vy += this.gravity;
        this.lifetime--;
        this.opacity = this.lifetime / this.maxLifetime;
    }

    /**
     * Desenha partícula
     */
    draw(ctx) {
        ctx.globalAlpha = this.opacity;
        ctx.fillStyle = this.color;
        ctx.shadowColor = this.color;
        ctx.shadowBlur = 5;
        ctx.fillRect(this.x, this.y, this.width, this.height);
        ctx.shadowColor = 'transparent';
        ctx.globalAlpha = 1;
    }

    /**
     * Verifica se a partícula está morta
     */
    isDead() {
        return this.lifetime <= 0;
    }
}

/**
 * Gerenciador de partículas
 */
class ParticleManager {
    constructor() {
        this.particles = [];
    }

    /**
     * Cria explosão
     */
    createExplosion(x, y, count = 8, force = 3) {
        for (let i = 0; i < count; i++) {
            const angle = (i / count) * Math.PI * 2;
            const vx = Math.cos(angle) * force;
            const vy = Math.sin(angle) * force;
            const particle = new Particle(x, y, vx, vy, 40, 2);
            particle.color = '#ff6600';
            this.particles.push(particle);
        }
    }

    /**
     * Cria partículas de impacto
     */
    createImpact(x, y, count = 5) {
        for (let i = 0; i < count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const force = Math.random() * 2 + 1;
            const vx = Math.cos(angle) * force;
            const vy = Math.sin(angle) * force;
            const particle = new Particle(x, y, vx, vy, 20, 2);
            particle.color = '#ffff00';
            this.particles.push(particle);
        }
    }

    /**
     * Adiciona partícula customizada
     */
    addParticle(particle) {
        this.particles.push(particle);
    }

    /**
     * Atualiza todas as partículas
     */
    update() {
        for (let i = this.particles.length - 1; i >= 0; i--) {
            const particle = this.particles[i];
            particle.update();
            if (particle.isDead()) {
                this.particles.splice(i, 1);
            }
        }
    }

    /**
     * Desenha todas as partículas
     */
    draw(ctx) {
        this.particles.forEach(particle => particle.draw(ctx));
    }

    /**
     * Limpa todas as partículas
     */
    clear() {
        this.particles = [];
    }
}
"},{"path":"js/enemies.js","content":"/**
 * GALAGA ARCADE - Inimigos
 * Sistema de inimigos com IA e padrões de ataque
 */

const EnemyTypes = {
    NORMAL: 'normal',
    STRONG: 'strong',
    BOSS: 'boss'
};

/**
 * Classe para inimigos
 */
class Enemy extends GameObject {
    constructor(x, y, type = EnemyTypes.NORMAL) {
        super(x, y, 18, 16);
        this.type = type;
        this.speed = 1;
        this.health = type === EnemyTypes.STRONG ? 2 : (type === EnemyTypes.BOSS ? 5 : 1);
        this.maxHealth = this.health;
        this.shootCooldown = 0;
        this.shootInterval = type === EnemyTypes.BOSS ? 20 : (type === EnemyTypes.STRONG ? 40 : 60);
        this.direction = 1;
        this.movePattern = 'sine'; // sine, square, line
        this.patternTime = 0;
        this.score = type === EnemyTypes.STRONG ? 25 : (type === EnemyTypes.BOSS ? 500 : 10);
    }

    /**
     * Atualiza inimigo
     */
    update(canvasWidth) {
        this.patternTime++;

        // Padrão de movimento
        switch (this.movePattern) {
            case 'sine':
                this.x += Math.sin(this.patternTime * 0.05) * this.speed;
                break;
            case 'square':
                if (this.patternTime % 60 < 30) {
                    this.x += this.speed;
                } else {
                    this.x -= this.speed;
                }
                break;
            case 'line':
                this.x += this.direction * this.speed;
                if (this.x < 0 || this.x + this.width > canvasWidth) {
                    this.direction *= -1;
                }
                break;
        }

        // Descida gradual
        this.y += 0.1;

        // Atualiza cooldown de tiro
        this.shootCooldown++;
    }

    /**
     * Tenta atirar
     */
    tryShoot(playerX) {
        if (this.shootCooldown >= this.shootInterval) {
            this.shootCooldown = 0;

            // Calcula ângulo para o jogador (para boss)
            let vx = 0;
            let vy = 3;

            if (this.type === EnemyTypes.BOSS) {
                const dx = playerX - this.x;
                const dist = Math.abs(dx) + 1;
                vx = (dx / dist) * 2;
            }

            return new Bullet(
                this.x + this.width / 2 - 2,
                this.y + this.height,
                vx,
                vy,
                false
            );
        }
        return null;
    }

    /**
     * Toma dano
     */
    takeDamage(amount = 1) {
        this.health -= amount;
        return this.health <= 0;
    }

    /**
     * Desenha inimigo
     */
    draw(ctx) {
        let color;
        if (this.type === EnemyTypes.BOSS) {
            color = '#ff6600';
        } else if (this.type === EnemyTypes.STRONG) {
            color = '#ff0080';
        } else {
            color = '#ff00ff';
        }

        ctx.fillStyle = color;
        ctx.shadowColor = color;
        ctx.shadowBlur = this.type === EnemyTypes.BOSS ? 15 : 10;

        // Desenha corpo do inimigo
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y);
        ctx.lineTo(this.x + this.width, this.y + 8);
        ctx.lineTo(this.x + this.width - 3, this.y + this.height);
        ctx.lineTo(this.x + 3, this.y + this.height);
        ctx.lineTo(this.x, this.y + 8);
        ctx.closePath();
        ctx.fill();

        // Olhos
        ctx.fillStyle = '#ffff00';
        ctx.fillRect(this.x + 5, this.y + 4, 2, 2);
        ctx.fillRect(this.x + this.width - 7, this.y + 4, 2, 2);

        // Barra de vida para boss
        if (this.type === EnemyTypes.BOSS) {
            const healthBarWidth = this.width;
            const healthBarHeight = 2;
            ctx.fillStyle = '#333';
            ctx.fillRect(this.x, this.y - 5, healthBarWidth, healthBarHeight);
            ctx.fillStyle = '#00ff00';
            const healthPercent = this.health / this.maxHealth;
            ctx.fillRect(this.x, this.y - 5, healthBarWidth * healthPercent, healthBarHeight);
        }

        ctx.shadowColor = 'transparent';
    }
}

/**
 * Gerenciador de inimigos
 */
class EnemyManager {
    constructor() {
        this.enemies = [];
        this.waveNumber = 0;
        this.spawnDelay = 0;
        this.spawnRate = 30;
    }

    /**
     * Gera nova onda de inimigos
     */
    spawnWave(level, canvasWidth, canvasHeight) {
        this.enemies = [];
        const enemyCount = 6 + Math.floor(level / 2);
        const columns = Math.min(8, enemyCount);
        const rows = Math.ceil(enemyCount / columns);
        const spacing = (canvasWidth - 80) / columns;

        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < columns; c++) {
                if (this.enemies.length >= enemyCount) break;

                const x = 40 + c * spacing;
                const y = 30 + r * 50;
                let type = EnemyTypes.NORMAL;

                // Alguns inimigos são mais fortes
                if (Math.random() < level * 0.1) {
                    type = EnemyTypes.STRONG;
                }

                const enemy = new Enemy(x, y, type);
                enemy.speed = 1 + (level - 1) * 0.3;

                this.enemies.push(enemy);
            }
        }

        // Boss a cada 5 níveis
        if (level % 5 === 0) {
            const boss = new Enemy(canvasWidth / 2 - 15, 20, EnemyTypes.BOSS);
            boss.speed = 0.5 + (level - 1) * 0.1;
            this.enemies.push(boss);
        }
    }

    /**
     * Atualiza inimigos
     */
    update(canvasWidth, canvasHeight) {
        this.enemies.forEach(enemy => {
            enemy.update(canvasWidth);
        });

        // Remove inimigos fora da tela
        this.enemies = this.enemies.filter(enemy => {
            return enemy.y < canvasHeight + 50;
        });
    }

    /**
     * Tenta disparos dos inimigos
     */
    tryShoot(playerX) {
        const bullets = [];
        this.enemies.forEach(enemy => {
            const bullet = enemy.tryShoot(playerX);
            if (bullet) bullets.push(bullet);
        });
        return bullets;
    }

    /**
     * Desenha inimigos
     */
    draw(ctx) {
        this.enemies.forEach(enemy => enemy.draw(ctx));
    }

    /**
     * Remove inimigo
     */
    removeEnemy(enemy) {
        const index = this.enemies.indexOf(enemy);
        if (index > -1) {
            this.enemies.splice(index, 1);
        }
    }

    /**
     * Verifica se todos os inimigos foram destruídos
     */
    isAllDefeated() {
        return this.enemies.length === 0;
    }

    /**
     * Obtém quantidade de inimigos
     */
    getCount() {
        return this.enemies.length;
    }

    /**
     * Limpa inimigos
     */
    clear() {
        this.enemies = [];
    }
}
