{"branch": "main", "files": [{"content":"/**
 * GALAGA ARCADE - Motor do Jogo Principal
 * Loop de jogo e controle geral
 */

// ===========================
// CONSTANTES DO JOGO
// ===========================

const GAME_WIDTH = 800;
const GAME_HEIGHT = 600;
const PLAYER_SPEED = 5;
const BULLET_SPEED = 7;
const MAX_LEVELS = 10;

// ===========================
// CLASS GAME
// ===========================

class Game {
    constructor(canvasId = 'gameCanvas') {
        this.canvas = document.getElementById(canvasId);
        this.ctx = this.canvas.getContext('2d');

        // Objetos do jogo
        this.player = new Player(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
        this.enemies = new EnemyManager();
        this.bullets = new BulletManager();
        this.particles = new ParticleManager();
        this.gameState = new GameStateManager();

        // Controles
        this.keys = {};
        this.touchX = null;
        this.touchActive = false;

        // Sistema de som
        this.audio = initAudio();

        // Timing
        this.lastTime = Date.now();
        this.deltaTime = 0;
        this.fps = 0;
        this.frameCount = 0;

        // Estado de pausa
        this.isPaused = false;
        this.levelUpTimer = 0;
        this.levelUpDuration = 180; // 3 segundos a 60 FPS

        // Inicializa
        this.init();
    }

    /**
     * Inicializa o jogo
     */
    init() {
        this.setupEventListeners();
        this.setupTouchControls();
        this.enemies.spawnWave(this.gameState.level, GAME_WIDTH, GAME_HEIGHT);
        this.updateUI();
        this.startGameLoop();
    }

    /**
     * Configura listeners de eventos
     */
    setupEventListeners() {
        // Teclado
        document.addEventListener('keydown', (e) => {
            this.keys[e.key] = true;

            // Controles especiais
            if (e.key === ' ') {
                e.preventDefault();
                if (this.gameState.isState(GameStates.MENU)) {
                    this.startGame();
                } else if (this.gameState.isState(GameStates.GAME_OVER)) {
                    this.restart();
                }
            }

            if (e.key === 'p' || e.key === 'P') {
                this.togglePause();
            }

            if (e.key === 'r' || e.key === 'R') {
                if (this.gameState.isState(GameStates.GAME_OVER)) {
                    this.restart();
                }
            }
        });

        document.addEventListener('keyup', (e) => {
            this.keys[e.key] = false;
        });

        // Botões do menu
        const restartBtn = getElement('restartBtn');
        if (restartBtn) {
            restartBtn.addEventListener('click', () => this.restart());
        }

        // Modal de pausa
        const pauseMenu = getElement('pauseMenu');
        if (pauseMenu) {
            pauseMenu.addEventListener('click', () => {
                if (this.gameState.isState(GameStates.PAUSED)) {
                    this.togglePause();
                }
            });
        }

        // Evitar comportamento padrão
        this.canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            this.audio.resumeAudioContext();
        });
    }

    /**
     * Configura controles de toque
     */
    setupTouchControls() {
        if (!isTouchDevice()) return;

        const touchControls = getElement('touchControls');
        if (!touchControls) return;

        if (isMobileDevice()) {
            addClass(touchControls, 'visible');
            addClass(getElement('controls-desktop'), 'hidden');
            removeClass(getElement('controls-mobile'), 'hidden');
        }

        // Toque na tela para atirar
        this.canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            if (this.gameState.isState(GameStates.PLAYING)) {
                const touch = e.touches[0];
                this.touchX = touch.clientX;
                this.touchActive = true;
            }
        });

        this.canvas.addEventListener('touchmove', (e) => {
            e.preventDefault();
            if (this.gameState.isState(GameStates.PLAYING) && this.touchActive) {
                const touch = e.touches[0];
                const rect = this.canvas.getBoundingClientRect();
                const x = touch.clientX - rect.left;

                // Converte coordenada de tela para canvas
                const canvasX = (x / rect.width) * GAME_WIDTH;
                this.player.x = clamp(canvasX - this.player.width / 2, 0, GAME_WIDTH - this.player.width);
            }
        });

        this.canvas.addEventListener('touchend', (e) => {
            e.preventDefault();
            this.touchActive = false;
        });

        // Botões de toque
        const touchLeft = getElement('touchLeft');
        const touchRight = getElement('touchRight');
        const touchShoot = getElement('touchShoot');

        if (touchLeft) {
            touchLeft.addEventListener('touchstart', () => { this.keys['ArrowLeft'] = true; });
            touchLeft.addEventListener('touchend', () => { this.keys['ArrowLeft'] = false; });
        }

        if (touchRight) {
            touchRight.addEventListener('touchstart', () => { this.keys['ArrowRight'] = true; });
            touchRight.addEventListener('touchend', () => { this.keys['ArrowRight'] = false; });
        }

        if (touchShoot) {
            touchShoot.addEventListener('touchstart', (e) => {
                e.preventDefault();
                this.keys[' '] = true;
            });
            touchShoot.addEventListener('touchend', () => { this.keys[' '] = false; });
        }
    }

    /**
     * Inicia o jogo
     */
    startGame() {
        this.gameState.reset();
        this.enemies.spawnWave(this.gameState.level, GAME_WIDTH, GAME_HEIGHT);
        this.bullets.clear();
        this.particles.clear();
        this.player.reset(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
        this.updateUI();
        setText('status', `Nível ${this.gameState.level} - Prepare-se!`);
    }

    /**
     * Alterna pausa
     */
    togglePause() {
        if (this.gameState.isState(GameStates.PLAYING)) {
            this.isPaused = true;
            this.gameState.setState(GameStates.PAUSED);
            removeClass(getElement('pauseMenu'), 'hidden');
        } else if (this.gameState.isState(GameStates.PAUSED)) {
            this.isPaused = false;
            this.gameState.setState(GameStates.PLAYING);
            addClass(getElement('pauseMenu'), 'hidden');
        }
    }

    /**
     * Reinicia o jogo
     */
    restart() {
        addClass(getElement('gameOverMenu'), 'hidden');
        this.startGame();
    }

    /**
     * Atualiza UI
     */
    updateUI() {
        updateScore('score', this.gameState.score);
        updateScore('highScore', this.gameState.highScore);
        setText('level', String(this.gameState.level));
        setText('lives', String(this.gameState.lives));
    }

    /**
     * Loop de atualização
     */
    update() {
        if (!this.gameState.isState(GameStates.PLAYING)) {
            return;
        }

        // Atualiza jogador
        this.player.update(this.keys, this.canvas);

        // Jogador atira
        if (this.keys[' ']) {
            const bullet = this.player.shoot();
            if (bullet) {
                this.bullets.addPlayerBullet(bullet);
            }
        }

        // Atualiza inimigos
        this.enemies.update(GAME_WIDTH, GAME_HEIGHT);

        // Inimigos atiram
        const enemyBullets = this.enemies.tryShoot(this.player.x);
        enemyBullets.forEach(bullet => this.bullets.addEnemyBullet(bullet));

        // Atualiza projéteis
        this.bullets.update(GAME_WIDTH, GAME_HEIGHT);

        // Atualiza partículas
        this.particles.update();

        // Colisões: projéteis do jogador vs inimigos
        this.checkPlayerBulletCollisions();

        // Colisões: projéteis dos inimigos vs jogador
        this.checkEnemyBulletCollisions();

        // Colisões: inimigos vs jogador
        this.checkEnemyPlayerCollisions();

        // Verifica fim de nível
        if (this.enemies.isAllDefeated()) {
            this.nextLevel();
        }

        // Verifica game over
        if (this.gameState.lives <= 0) {
            this.gameOver();
        }
    }

    /**
     * Verifica colisões dos projéteis do jogador
     */
    checkPlayerBulletCollisions() {
        for (let i = this.bullets.playerBullets.length - 1; i >= 0; i--) {
            const bullet = this.bullets.playerBullets[i];
            let hit = false;

            for (let j = this.enemies.enemies.length - 1; j >= 0; j--) {
                const enemy = this.enemies.enemies[j];
                if (checkCollision(bullet.getRect(), enemy.getRect())) {
                    hit = true;

                    if (enemy.takeDamage(bullet.damage)) {
                        // Inimigo destruído
                        this.gameState.addScore(enemy.score * this.gameState.getDifficultyMultiplier());
                        this.particles.createExplosion(enemy.x + enemy.width / 2, enemy.y + enemy.height / 2);
                        this.audio.playExplosion();
                        this.enemies.removeEnemy(enemy);
                    } else {
                        // Inimigo ferido
                        this.particles.createImpact(enemy.x + enemy.width / 2, enemy.y);
                    }
                    break;
                }
            }

            if (hit) {
                this.bullets.playerBullets.splice(i, 1);
            }
        }
    }

    /**
     * Verifica colisões dos projéteis dos inimigos
     */
    checkEnemyBulletCollisions() {
        for (let i = this.bullets.enemyBullets.length - 1; i >= 0; i--) {
            const bullet = this.bullets.enemyBullets[i];
            if (checkCollision(bullet.getRect(), this.player.getRect())) {
                if (this.player.takeDamage(1)) {
                    if (!this.gameState.loseLife()) {
                        this.gameOver();
                    } else {
                        this.player.reset(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
                    }
                }
                this.particles.createExplosion(this.player.x + this.player.width / 2, this.player.y);
                this.bullets.enemyBullets.splice(i, 1);
            }
        }
    }

    /**
     * Verifica colisões dos inimigos com o jogador
     */
    checkEnemyPlayerCollisions() {
        for (let i = this.enemies.enemies.length - 1; i >= 0; i--) {
            const enemy = this.enemies.enemies[i];
            if (checkCollision(enemy.getRect(), this.player.getRect())) {
                if (!this.player.invincible) {
                    if (this.player.takeDamage(1)) {
                        if (!this.gameState.loseLife()) {
                            this.gameOver();
                        } else {
                            this.player.reset(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
                        }
                    }
                    this.particles.createExplosion(this.player.x + this.player.width / 2, this.player.y);
                }
            }
        }
    }

    /**
     * Próximo nível
     */
    nextLevel() {
        this.gameState.nextLevel();
        this.levelUpTimer = this.levelUpDuration;
        setText('status', `🎉 NÍVEL ${this.gameState.level - 1} COMPLETO! 🎉`);
        this.audio.playLevelUp();
    }

    /**
     * Game over
     */
    gameOver() {
        this.gameState.setState(GameStates.GAME_OVER);
        setText('finalScore', String(this.gameState.score).padStart(6, '0'));

        if (this.gameState.isNewRecord) {
            removeClass(getElement('newRecord'), 'hidden');
        } else {
            addClass(getElement('newRecord'), 'hidden');
        }

        removeClass(getElement('gameOverMenu'), 'hidden');
        setText('status', 'GAME OVER');
        this.audio.playGameOver();
    }

    /**
     * Loop de renderização
     */
    draw() {
        // Limpa canvas
        this.ctx.fillStyle = '#000000';
        this.ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

        // Grade de fundo (efeito retrô)
        this.ctx.strokeStyle = 'rgba(0, 255, 0, 0.03)';
        this.ctx.lineWidth = 1;
        for (let i = 0; i < GAME_WIDTH; i += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(i, 0);
            this.ctx.lineTo(i, GAME_HEIGHT);
            this.ctx.stroke();
        }
        for (let i = 0; i < GAME_HEIGHT; i += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, i);
            this.ctx.lineTo(GAME_WIDTH, i);
            this.ctx.stroke();
        }

        // Desenha objetos
        this.player.draw(this.ctx);
        this.enemies.draw(this.ctx);
        this.bullets.draw(this.ctx);
        this.particles.draw(this.ctx);

        // Texto da transição de nível
        if (this.levelUpTimer > 0) {
            this.levelUpTimer--;
            const alpha = Math.min(1, Math.max(0, (this.levelUpDuration - this.levelUpTimer) / 20));
            this.ctx.globalAlpha = alpha;
            this.ctx.fillStyle = '#ffff00';
            this.ctx.font = 'bold 30px Arial';
            this.ctx.textAlign = 'center';
            this.ctx.shadowColor = 'rgba(255, 255, 0, 0.8)';
            this.ctx.shadowBlur = 20;
            this.ctx.fillText('PRÓXIMO NÍVEL!', GAME_WIDTH / 2, GAME_HEIGHT / 2);
            this.ctx.globalAlpha = 1;
            this.ctx.shadowColor = 'transparent';

            if (this.levelUpTimer === 0) {
                this.enemies.spawnWave(this.gameState.level, GAME_WIDTH, GAME_HEIGHT);
                this.bullets.clear();
                this.gameState.setState(GameStates.PLAYING);
            }
        }
    }

    /**
     * Inicia o loop do jogo
     */
    startGameLoop() {
        const gameLoop = () => {
            const currentTime = Date.now();
            this.deltaTime = Math.min((currentTime - this.lastTime) / 16.67, 2); // Máximo 2 frames
            this.lastTime = currentTime;

            // Atualiza
            if (!this.isPaused && !this.gameState.isState(GameStates.PAUSED)) {
                this.update();
            }

            // Desenha
            this.draw();

            // Atualiza UI
            this.updateUI();

            // Próximo frame
            requestAnimationFrame(gameLoop);
        };

        requestAnimationFrame(gameLoop);
    }
}

