   GALAGA ARCADE - Estilos
   =========================== */

:root {
    --color-bg: #000000;
    --color-text: #00ff00;
    --color-text-alt: #ffff00;
    --color-player: #00ff00;
    --color-enemy: #ff00ff;
    --color-enemy-strong: #ff0080;
    --color-boss: #ff6600;
    --color-bullet: #ffff00;
    --color-enemy-bullet: #ff0000;
    --color-particle: #00ffff;
    --color-border: #0099ff;
    --font-arcade: 'Press Start 2P', cursive;
    --shadow-glow: 0 0 20px rgba(0, 255, 0, 0.8);
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html, body {
    width: 100%;
    height: 100%;
    background: var(--color-bg);
    color: var(--color-text);
    font-family: var(--font-arcade);
    overflow: hidden;
    user-select: none;
    -webkit-user-select: none;
    -webkit-touch-callout: none;
}

body {
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    width: 100%;
    max-width: 900px;
    padding: 10px;
    display: flex;
    flex-direction: column;
    gap: 10px;
}

/* ===========================
   HEADER & SCOREBOARD
   =========================== */

.header {
    text-align: center;
    border: 3px solid var(--color-border);
    background: linear-gradient(135deg, rgba(0, 153, 255, 0.2), rgba(0, 255, 0, 0.1));
    padding: 15px;
    box-shadow: var(--shadow-glow), inset 0 0 10px rgba(0, 255, 0, 0.3);
}

.title {
    font-size: 28px;
    color: var(--color-text-alt);
    text-shadow: 0 0 10px var(--color-text-alt), 0 0 20px rgba(255, 255, 0, 0.5);
    margin-bottom: 10px;
    letter-spacing: 2px;
    animation: pulse 2s infinite;
}

@keyframes pulse {
    0%, 100% {
        text-shadow: 0 0 10px var(--color-text-alt);
    }
    50% {
        text-shadow: 0 0 20px var(--color-text-alt), 0 0 30px rgba(255, 255, 0, 0.8);
    }
}

.score-board {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 15px;
    margin-top: 10px;
}

.score-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 5px;
    padding: 10px;
    border: 2px solid var(--color-border);
    background: rgba(0, 99, 153, 0.3);
    border-radius: 5px;
}

.score-item .label {
    font-size: 10px;
    color: var(--color-text);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.score-item .value {
    font-size: 14px;
    color: var(--color-text-alt);
    text-shadow: 0 0 10px var(--color-text-alt);
}

/* ===========================
   GAME CANVAS
   =========================== */

.game-wrapper {
    width: 100%;
    max-width: 800px;
    margin: 0 auto;
    border: 4px solid var(--color-border);
    box-shadow: 0 0 30px rgba(0, 255, 0, 0.6), inset 0 0 20px rgba(0, 0, 0, 0.8);
    background: var(--color-bg);
    aspect-ratio: 4/3;
}

#gameCanvas {
    width: 100%;
    height: 100%;
    display: block;
    background: var(--color-bg);
}

/* ===========================
   STATUS BAR
   =========================== */

.status-bar {
    text-align: center;
    padding: 8px;
    background: rgba(0, 0, 0, 0.7);
    border: 2px solid var(--color-border);
    color: var(--color-text);
    font-size: 12px;
    min-height: 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 0 10px rgba(0, 255, 0, 0.3);
}

/* ===========================
   CONTROLS INFO
   =========================== */

.controls {
    font-size: 10px;
    color: var(--color-text);
    text-align: center;
    gap: 10px;
    display: flex;
    flex-direction: column;
}

.controls p {
    margin: 5px 0;
    padding: 8px;
    background: rgba(0, 0, 0, 0.5);
    border: 1px solid var(--color-border);
    border-radius: 3px;
}

.controls-mobile {
    display: none;
}

/* ===========================
   MODAL (Pause/GameOver)
   =========================== */

.modal {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.9);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
    border: 2px solid var(--color-text-alt);
}

.modal.hidden {
    display: none;
}

.modal-content {
    background: linear-gradient(135deg, rgba(0, 0, 0, 0.95), rgba(0, 50, 100, 0.8));
    border: 4px solid var(--color-text-alt);
    padding: 40px;
    text-align: center;
    border-radius: 10px;
    box-shadow: 0 0 50px var(--color-text-alt), inset 0 0 30px rgba(0, 255, 0, 0.3);
    animation: scaleIn 0.3s ease-out;
}

@keyframes scaleIn {
    from {
        transform: scale(0.5);
        opacity: 0;
    }
    to {
        transform: scale(1);
        opacity: 1;
    }
}

.modal-content h2 {
    font-size: 32px;
    color: var(--color-text-alt);
    margin-bottom: 20px;
    text-shadow: 0 0 20px var(--color-text-alt);
}

.modal-content p {
    font-size: 14px;
    color: var(--color-text);
    margin: 10px 0;
}

.modal-content #newRecord {
    color: var(--color-text-alt);
    font-size: 16px;
    animation: blink 0.5s infinite;
}

@keyframes blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
}

#newRecord.hidden {
    display: none;
}

/* ===========================
   BUTTONS
   =========================== */

.btn {
    margin-top: 20px;
    padding: 12px 24px;
    font-size: 12px;
    font-family: var(--font-arcade);
    background: linear-gradient(135deg, var(--color-text-alt), #ffcc00);
    color: #000;
    border: 2px solid var(--color-text-alt);
    cursor: pointer;
    border-radius: 5px;
    transition: all 0.2s;
    box-shadow: 0 0 10px rgba(255, 255, 0, 0.5);
}

.btn:hover {
    transform: scale(1.05);
    box-shadow: 0 0 20px rgba(255, 255, 0, 0.8);
}

.btn:active {
    transform: scale(0.95);
}

/* ===========================
   TOUCH CONTROLS
   =========================== */

.touch-controls {
    display: none;
    position: fixed;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 120px;
    background: rgba(0, 0, 0, 0.8);
    border-top: 2px solid var(--color-border);
    z-index: 100;
}

.touch-controls.visible {
    display: flex;
}

.touch-pad {
    display: flex;
    width: 100%;
    height: 100%;
    gap: 2px;
    padding: 5px;
}

.touch-zone {
    flex: 1;
    border: 2px solid var(--color-border);
    background: rgba(0, 255, 0, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 12px;
    color: var(--color-text);
    cursor: pointer;
    user-select: none;
    -webkit-user-select: none;
    transition: background 0.1s;
}

.touch-zone:active {
    background: rgba(0, 255, 0, 0.3);
    box-shadow: inset 0 0 10px rgba(0, 255, 0, 0.5);
}

.touch-zone.left::before {
    content: "◄";
}

.touch-zone.right::before {
    content: "►";
}

.touch-zone.shoot::before {
    content: "ATIRAR";
    font-size: 14px;
}

/* ===========================
   RESPONSIVE DESIGN
   =========================== */

/* Tablets */
@media (max-width: 768px) {
    .header {
        padding: 10px;
    }

    .title {
        font-size: 20px;
    }

    .score-board {
        grid-template-columns: repeat(2, 1fr);
        gap: 10px;
    }

    .score-item .label {
        font-size: 8px;
    }

    .score-item .value {
        font-size: 12px;
    }

    .controls p {
        font-size: 9px;
    }

    .game-wrapper {
        max-width: 100%;
    }
}

/* Smartphones */
@media (max-width: 480px) {
    body {
        height: 100vh;
        height: 100dvh;
    }

    .container {
        max-width: 100%;
        padding: 5px;
        gap: 5px;
        height: 100%;
    }

    .header {
        padding: 8px;
        border-width: 2px;
    }

    .title {
        font-size: 16px;
        margin-bottom: 8px;
    }

    .score-board {
        grid-template-columns: repeat(2, 1fr);
        gap: 8px;
        margin-top: 8px;
    }

    .score-item {
        padding: 8px;
        border-width: 1px;
        gap: 3px;
    }

    .score-item .label {
        font-size: 7px;
    }

    .score-item .value {
        font-size: 11px;
    }

    .game-wrapper {
        max-width: 100%;
        border-width: 2px;
        flex: 1;
    }

    #gameCanvas {
        width: 100%;
        height: 100%;
    }

    .status-bar {
        padding: 5px;
        font-size: 10px;
        border-width: 1px;
        min-height: 25px;
    }

    .controls {
        font-size: 8px;
        gap: 5px;
    }

    .controls p {
        margin: 3px 0;
        padding: 5px;
        border-width: 1px;
    }

    .controls-desktop {
        display: none;
    }

    .controls-mobile {
        display: block;
    }

    .touch-controls.visible {
        height: 100px;
        padding: 3px;
    }

    .touch-zone {
        font-size: 10px;
        border-width: 1px;
    }

    .modal-content {
        padding: 20px;
        border-width: 2px;
    }

    .modal-content h2 {
        font-size: 20px;
        margin-bottom: 15px;
    }

    .modal-content p {
        font-size: 11px;
    }

    .btn {
        padding: 10px 15px;
        font-size: 10px;
        margin-top: 15px;
    }
}

/* ===========================
   ANIMATIONS
   =========================== */

@keyframes flicker {
    0%, 19%, 21%, 23%, 25%, 54%, 56%, 100% {
        opacity: 1;
    }
    20%, 24%, 55% {
        opacity: 0.8;
    }
}

@keyframes glow {
    0%, 100% {
        text-shadow: 0 0 10px var(--color-text-alt);
    }
    50% {
        text-shadow: 0 0 20px var(--color-text-alt), 0 0 30px rgba(255, 255, 0, 0.6);
    }
}

/* Suporta modo escuro nativo */
@media (prefers-color-scheme: dark) {
    :root {
        --color-bg: #000000;
    }
}"},{"path":"js/utils.js","content":"/**
 * GALAGA ARCADE - Utilitários
 * Funções auxiliares e classes base
 */

// ===========================
// UTILIDADES GERAIS
// ===========================

/**
 * Gera um número aleatório entre min e max
 */
function random(min, max) {
    return Math.random() * (max - min) + min;
}

/**
 * Gera um número inteiro aleatório entre min e max
 */
function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Detecta colisão entre dois retângulos
 */
function checkCollision(rect1, rect2) {
    return rect1.x < rect2.x + rect2.width &&
           rect1.x + rect1.width > rect2.x &&
           rect1.y < rect2.y + rect2.height &&
           rect1.y + rect1.height > rect2.y;
}

/**
 * Detecta colisão entre círculo e retângulo
 */
function checkCircleRectCollision(circle, rect) {
    const closestX = Math.max(rect.x, Math.min(circle.x, rect.x + rect.width));
    const closestY = Math.max(rect.y, Math.min(circle.y, rect.y + rect.height));

    const distX = circle.x - closestX;
    const distY = circle.y - closestY;

    return (distX * distX + distY * distY) < (circle.radius * circle.radius);
}

/**
 * Limita um valor entre min e max
 */
function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
}

/**
 * Interpola linearmente entre dois valores
 */
function lerp(a, b, t) {
    return a + (b - a) * t;
}

/**
 * Calcula distância entre dois pontos
 */
function distance(x1, y1, x2, y2) {
    const dx = x2 - x1;
    const dy = y2 - y1;
    return Math.sqrt(dx * dx + dy * dy);
}

/**
 * Calcula ângulo entre dois pontos (em radianos)
 */
function getAngle(x1, y1, x2, y2) {
    return Math.atan2(y2 - y1, x2 - x1);
}

/**
 * Converte graus para radianos
 */
function degToRad(deg) {
    return deg * (Math.PI / 180);
}

/**
 * Converte radianos para graus
 */
function radToDeg(rad) {
    return rad * (180 / Math.PI);
}

// ===========================
// DETECÇÃO DE DISPOSITIVO
// ===========================

/**
 * Detecta se é um dispositivo móvel
 */
function isMobileDevice() {
    return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
}

/**
 * Detecta se tem suporte a touch
 */
function isTouchDevice() {
    return (
        (typeof window !== 'undefined' &&
            ('ontouchstart' in window ||
             navigator.maxTouchPoints > 0 ||
             navigator.msMaxTouchPoints > 0))
    );
}

// ===========================
// MANIPULAÇÃO DE DOM
// ===========================

/**
 * Obtém elemento por ID com segurança
 */
function getElement(id) {
    return document.getElementById(id);
}

/**
 * Define classe CSS com toggle
 */
function toggleClass(element, className) {
    if (element) {
        element.classList.toggle(className);
    }
}

/**
 * Adiciona classe CSS
 */
function addClass(element, className) {
    if (element) {
        element.classList.add(className);
    }
}

/**
 * Remove classe CSS
 */
function removeClass(element, className) {
    if (element) {
        element.classList.remove(className);
    }
}

/**
 * Verifica se elemento tem classe
 */
function hasClass(element, className) {
    return element && element.classList.contains(className);
}

/**
 * Define texto do elemento
 */
function setText(id, text) {
    const element = getElement(id);
    if (element) {
        element.textContent = text;
    }
}

/**
 * Atualiza texto formatado com número
 */
function updateScore(id, value) {
    setText(id, String(value).padStart(6, '0'));
}

// ===========================
// ARMAZENAMENTO LOCAL
// ===========================

/**
 * Obtém valor do localStorage
 */
function getLocalStorage(key, defaultValue = null) {
    try {
        const value = localStorage.getItem(key);
        return value ? JSON.parse(value) : defaultValue;
    } catch (e) {
        console.warn('localStorage read error:', e);
        return defaultValue;
    }
}

/**
 * Define valor no localStorage
 */
function setLocalStorage(key, value) {
    try {
        localStorage.setItem(key, JSON.stringify(value));
        return true;
    } catch (e) {
        console.warn('localStorage write error:', e);
        return false;
    }
}

/**
 * Remove valor do localStorage
 */
function removeLocalStorage(key) {
    try {
        localStorage.removeItem(key);
        return true;
    } catch (e) {
        console.warn('localStorage remove error:', e);
        return false;
    }
}

// ===========================
// CLASSE BASE - GAMEOBJECT
// ===========================

/**
 * Classe base para todos os objetos do jogo
 */
class GameObject {
    constructor(x = 0, y = 0, width = 10, height = 10) {
        this.x = x;
        this.y = y;
        this.width = width;
        this.height = height;
        this.vx = 0;
        this.vy = 0;
        this.active = true;
    }

    /**
     * Atualiza a posição
     */
    update() {
        this.x += this.vx;
        this.y += this.vy;
    }

    /**
     * Desenha o objeto
     */
    draw(ctx) {
        ctx.fillStyle = '#fff';
        ctx.fillRect(this.x, this.y, this.width, this.height);
    }

    /**
     * Verifica se está fora da tela
     */
    isOutOfBounds(canvasWidth, canvasHeight, margin = 50) {
        return this.x + this.width < -margin ||
               this.x > canvasWidth + margin ||
               this.y + this.height < -margin ||
               this.y > canvasHeight + margin;
    }

    /**
     * Retorna rect para detecção de colisão
     */
    getRect() {
        return {
            x: this.x,
            y: this.y,
            width: this.width,
            height: this.height
        };
    }
}

// ===========================
// PERFORMANCE & DEBUG
// ===========================

/**
 * Conta frames por segundo
 */
class FPSCounter {
    constructor() {
        this.fps = 0;
        this.frameCount = 0;
        this.lastTime = Date.now();
    }

    update() {
        this.frameCount++;
        const currentTime = Date.now();
        const elapsed = currentTime - this.lastTime;

        if (elapsed >= 1000) {
            this.fps = this.frameCount;
            this.frameCount = 0;
            this.lastTime = currentTime;
        }

        return this.fps;
    }
}

// ===========================
// TIMER
// ===========================

/**
 * Timer simples
 */
class Timer {
    constructor(duration = 1000) {
        this.duration = duration;
        this.elapsed = 0;
        this.active = false;
    }

    start() {
        this.active = true;
        this.elapsed = 0;
    }

    stop() {
        this.active = false;
    }

    update(deltaTime = 16) {
        if (this.active) {
            this.elapsed += deltaTime;
            if (this.elapsed >= this.duration) {
                this.active = false;
                return true;
            }
        }
        return false;
    }

    getProgress() {
        return Math.min(1, this.elapsed / this.duration);
    }

    isFinished() {
        return !this.active && this.elapsed >= this.duration;
    }
}"},{"path":"js/gamestate.js","content":"/**
 * GALAGA ARCADE - Gerenciador de Estado
 * Controla os diferentes estados do jogo
 */

const GameStates = {
    MENU: 'menu',
    PLAYING: 'playing',
    PAUSED: 'paused',
    LEVEL_UP: 'levelup',
    GAME_OVER: 'gameover'
};

/**
 * Classe para gerenciar o estado do jogo
 */
class GameStateManager {
    constructor() {
        this.currentState = GameStates.MENU;
        this.previousState = null;
        this.score = 0;
        this.highScore = this.loadHighScore();
        this.level = 1;
        this.lives = 3;
        this.isNewRecord = false;
    }

    /**
     * Muda para novo estado
     */
    setState(newState) {
        this.previousState = this.currentState;
        this.currentState = newState;
    }

    /**
     * Verifica se está em determinado estado
     */
    isState(state) {
        return this.currentState === state;
    }

    /**
     * Adiciona pontos
     */
    addScore(points) {
        this.score += points;
        if (this.score > this.highScore) {
            this.highScore = this.score;
            this.isNewRecord = true;
            this.saveHighScore();
        }
    }

    /**
     * Reseta para novo jogo
     */
    reset() {
        this.score = 0;
        this.level = 1;
        this.lives = 3;
        this.isNewRecord = false;
        this.setState(GameStates.PLAYING);
    }

    /**
     * Próximo nível
     */
    nextLevel() {
        this.level++;
        this.setState(GameStates.LEVEL_UP);
    }

    /**
     * Perde uma vida
     */
    loseLife() {
        this.lives--;
        if (this.lives <= 0) {
            this.setState(GameStates.GAME_OVER);
            return false;
        }
        return true;
    }

    /**
     * Salva high score no localStorage
     */
    saveHighScore() {
        setLocalStorage('galaga_highscore', this.highScore);
    }

    /**
     * Carrega high score do localStorage
     */
    loadHighScore() {
        return getLocalStorage('galaga_highscore', 0);
    }

    /**
     * Retorna progresso para próximo level
     */
    getLevelProgress() {
        const maxLevel = 10;
        return Math.min(1, this.level / maxLevel);
    }

    /**
     * Retorna multiplicador de dificuldade
     */
    getDifficultyMultiplier() {
        return 1 + (this.level - 1) * 0.2;
    }
}"},{"path":"js/audio.js","content":"/**
 * GALAGA ARCADE - Sistema de Áudio
 * Gerencia efeitos sonoros e música
 */

/**
 * Gerenciador de áudio com Web Audio API
 */
class AudioManager {
    constructor() {
        this.audioContext = null;
        this.masterVolume = 0.3;
        this.soundEnabled = true;
        this.musicEnabled = true;
        this.initAudioContext();
    }

    /**
     * Inicializa contexto de áudio
     */
    initAudioContext() {
        try {
            const AudioContext = window.AudioContext || window.webkitAudioContext;
            if (AudioContext) {
                this.audioContext = new AudioContext();
            }
        } catch (e) {
            console.warn('Web Audio API não disponível:', e);
        }
    }

    /**
     * Certifica que o contexto de áudio está rodando
     */
    resumeAudioContext() {
        if (this.audioContext && this.audioContext.state === 'suspended') {
            this.audioContext.resume();
        }
    }

    /**
     * Toca som de tiro
     */
    playShoot() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playTone(400, 0.1, 0.05);
    }

    /**
     * Toca som de explosão
     */
    playExplosion() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playNoise(200, 0.3);
    }

    /**
     * Toca som de game over
     */
    playGameOver() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playTone(200, 0.3, 0.5);
    }

    /**
     * Toca som de nível completo
     */
    playLevelUp() {
        if (!this.soundEnabled || !this.audioContext) return;
        this.playTone(800, 0.2, 0.1);
    }

    /**
     * Toca tom de frequência específica
     */
    playTone(frequency, volume = 0.3, duration = 0.1) {
        if (!this.audioContext) return;

        try {
            const now = this.audioContext.currentTime;
            const osc = this.audioContext.createOscillator();
            const gain = this.audioContext.createGain();

            osc.connect(gain);
            gain.connect(this.audioContext.destination);

            osc.frequency.value = frequency;
            gain.gain.setValueAtTime(volume * this.masterVolume, now);
            gain.gain.exponentialRampToValueAtTime(0.01, now + duration);

            osc.start(now);
            osc.stop(now + duration);
        } catch (e) {
            console.warn('Erro ao tocar tom:', e);
        }
    }

    /**
     * Toca ruído
     */
    playNoise(duration = 0.2, volume = 0.3) {
        if (!this.audioContext) return;

        try {
            const now = this.audioContext.currentTime;
            const bufferSize = this.audioContext.sampleRate * duration;
            const buffer = this.audioContext.createBuffer(1, bufferSize, this.audioContext.sampleRate);
            const data = buffer.getChannelData(0);

            for (let i = 0; i < bufferSize; i++) {
                data[i] = Math.random() * 2 - 1;
            }

            const source = this.audioContext.createBufferSource();
            const gain = this.audioContext.createGain();

            source.buffer = buffer;
            source.connect(gain);
            gain.connect(this.audioContext.destination);

            gain.gain.setValueAtTime(volume * this.masterVolume, now);
            gain.gain.exponentialRampToValueAtTime(0.01, now + duration);

            source.start(now);
        } catch (e) {
            console.warn('Erro ao tocar ruído:', e);
        }
    }

    /**
     * Define volume mestre
     */
    setMasterVolume(volume) {
        this.masterVolume = clamp(volume, 0, 1);
    }

    /**
     * Alterna sons
     */
    toggleSound() {
        this.soundEnabled = !this.soundEnabled;
        return this.soundEnabled;
    }

    /**
     * Alterna música
     */
    toggleMusic() {
        this.musicEnabled = !this.musicEnabled;
        return this.musicEnabled;
    }
}

// Instância global do gerenciador de áudio
let audioManager = null;

/**
 * Inicializa o gerenciador de áudio
 */
function initAudio() {
    audioManager = new AudioManager();
    return audioManager;
}

/**
 * Obtém a instância do gerenciador de áudio
 */
function getAudioManager() {
    if (!audioManager) {
        audioManager = new AudioManager();
    }
    return audioManager;
}"},{"path":"js/player.js","content":"/**
 * GALAGA ARCADE - Jogador
 * Controla a nave do jogador
 */

class Player extends GameObject {
    constructor(x, y) {
        super(x, y, 20, 25);
        this.speed = 5;
        this.canShoot = true;
        this.shootCooldown = 0;
        this.maxHealth = 1;
        this.health = this.maxHealth;
        this.invincible = false;
        this.invincibilityDuration = 120; // frames
        this.invincibilityCounter = 0;
    }

    /**
     * Atualiza o jogador
     */
    update(keys, canvas) {
        // Movimento horizontal
        if (keys['ArrowLeft'] || keys['a']) {
            this.vx = -this.speed;
        } else if (keys['ArrowRight'] || keys['d']) {
            this.vx = this.speed;
        } else {
            this.vx = 0;
        }

        // Atualiza posição
        this.x += this.vx;

        // Limita ao canvas
        if (this.x < 0) this.x = 0;
        if (this.x + this.width > canvas.width) {
            this.x = canvas.width - this.width;
        }

        // Atualiza invencibilidade
        if (this.invincible) {
            this.invincibilityCounter++;
            if (this.invincibilityCounter >= this.invincibilityDuration) {
                this.invincible = false;
                this.invincibilityCounter = 0;
            }
        }

        // Atualiza cooldown de tiro
        if (this.shootCooldown > 0) {
            this.shootCooldown--;
        } else {
            this.canShoot = true;
        }
    }

    /**
     * Atira um projétil
     */
    shoot() {
        if (this.canShoot && this.shootCooldown <= 0) {
            this.shootCooldown = 8;
            this.canShoot = false;

            // Reproduz som de tiro
            if (audioManager) {
                audioManager.playShoot();
            }

            return new Bullet(
                this.x + this.width / 2 - 2,
                this.y,
                0,
                -7,
                true
            );
        }
        return null;
    }

    /**
     * Toma dano
     */
    takeDamage(amount = 1) {
        if (this.invincible) return;

        this.health -= amount;
        this.invincible = true;
        this.invincibilityCounter = 0;

        if (audioManager) {
            audioManager.playExplosion();
        }

        return this.health <= 0;
    }

    /**
     * Cura o jogador
     */
    heal(amount = 1) {
        this.health = Math.min(this.maxHealth, this.health + amount);
    }

    /**
     * Desenha o jogador
     */
    draw(ctx) {
        // Pisca se estiver invencível
        if (this.invincible && Math.floor(this.invincibilityCounter / 5) % 2 === 0) {
            return;
        }

        // Desenha nave
        ctx.fillStyle = '#00ff00';
        ctx.shadowColor = 'rgba(0, 255, 0, 0.8)';
        ctx.shadowBlur = 10;

        // Corpo da nave
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y);
        ctx.lineTo(this.x + this.width, this.y + this.height);
        ctx.lineTo(this.x + this.width - 5, this.y + this.height);
        ctx.lineTo(this.x + this.width / 2 + 3, this.y + 10);
        ctx.lineTo(this.x + this.width / 2 - 3, this.y + 10);
        ctx.lineTo(this.x + 5, this.y + this.height);
        ctx.lineTo(this.x, this.y + this.height);
        ctx.closePath();
        ctx.fill();

        // Visor
        ctx.fillStyle = '#ffff00';
        ctx.fillRect(this.x + this.width / 2 - 3, this.y + 5, 6, 3);

        ctx.shadowColor = 'transparent';
    }

    /**
     * Reseta o jogador
     */
    reset(x, y) {
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
        this.health = this.maxHealth;
        this.invincible = true;
        this.invincibilityCounter = 0;
    }
}"},{"path":"js/bullets.js","content":"/**
 * GALAGA ARCADE - Sistema de Projéteis
 * Gerencia projéteis do jogador e inimigos
 */

/**
 * Classe para projéteis
 */
class Bullet extends GameObject {
    constructor(x, y, vx, vy, isPlayerBullet = false) {
        super(x, y, 4, 10);
        this.vx = vx;
        this.vy = vy;
        this.isPlayerBullet = isPlayerBullet;
        this.damage = 1;
    }

    /**
     * Atualiza projétil
     */
    update() {
        this.x += this.vx;
        this.y += this.vy;
    }

    /**
     * Desenha projétil
     */
    draw(ctx) {
        if (this.isPlayerBullet) {
            ctx.fillStyle = '#ffff00';
            ctx.shadowColor = 'rgba(255, 255, 0, 0.8)';
        } else {
            ctx.fillStyle = '#ff0000';
            ctx.shadowColor = 'rgba(255, 0, 0, 0.6)';
        }
        ctx.shadowBlur = 5;
        ctx.fillRect(this.x, this.y, this.width, this.height);
        ctx.shadowColor = 'transparent';
    }
}

/**
 * Gerenciador de projéteis
 */
class BulletManager {
    constructor() {
        this.playerBullets = [];
        this.enemyBullets = [];
    }

    /**
     * Adiciona projétil do jogador
     */
    addPlayerBullet(bullet) {
        if (bullet) {
            this.playerBullets.push(bullet);
        }
    }

    /**
     * Adiciona projétil do inimigo
     */
    addEnemyBullet(bullet) {
        if (bullet) {
            this.enemyBullets.push(bullet);
        }
    }

    /**
     * Atualiza todos os projéteis
     */
    update(canvasWidth, canvasHeight) {
        // Atualiza projéteis do jogador
        for (let i = this.playerBullets.length - 1; i >= 0; i--) {
            const bullet = this.playerBullets[i];
            bullet.update();

            if (bullet.isOutOfBounds(canvasWidth, canvasHeight, 10)) {
                this.playerBullets.splice(i, 1);
            }
        }

        // Atualiza projéteis do inimigo
        for (let i = this.enemyBullets.length - 1; i >= 0; i--) {
            const bullet = this.enemyBullets[i];
            bullet.update();

            if (bullet.isOutOfBounds(canvasWidth, canvasHeight, 10)) {
                this.enemyBullets.splice(i, 1);
            }
        }
    }

    /**
     * Desenha todos os projéteis
     */
    draw(ctx) {
        this.playerBullets.forEach(bullet => bullet.draw(ctx));
        this.enemyBullets.forEach(bullet => bullet.draw(ctx));
    }

    /**
     * Remove todos os projéteis
     */
    clear() {
        this.playerBullets = [];
        this.enemyBullets = [];
    }

    /**
     * Remove projétil específico
     */
    removeBullet(bullet) {
        const pIndex = this.playerBullets.indexOf(bullet);
        if (pIndex > -1) {
            this.playerBullets.splice(pIndex, 1);
        }
        const eIndex = this.enemyBullets.indexOf(bullet);
        if (eIndex > -1) {
            this.enemyBullets.splice(eIndex, 1);
        }
    }
}"},{"path":"js/particles.js","content":"/**
 * GALAGA ARCADE - Sistema de Partículas
 * Efeitos visuais de explosões e impactos
 */

/**
 * Classe para partícula individual
 */
class Particle extends GameObject {
    constructor(x, y, vx, vy, lifetime = 30, size = 3) {
        super(x, y, size, size);
        this.vx = vx;
        this.vy = vy;
        this.lifetime = lifetime;
        this.maxLifetime = lifetime;
        this.gravity = 0.1;
        this.color = '#00ffff';
        this.opacity = 1;
    }

    /**
     * Atualiza partícula
     */
    update() {
        this.x += this.vx;
        this.y += this.vy;
        this.vy += this.gravity;
        this.lifetime--;
        this.opacity = this.lifetime / this.maxLifetime;
    }

    /**
     * Desenha partícula
     */
    draw(ctx) {
        ctx.globalAlpha = this.opacity;
        ctx.fillStyle = this.color;
        ctx.shadowColor = this.color;
        ctx.shadowBlur = 5;
        ctx.fillRect(this.x, this.y, this.width, this.height);
        ctx.shadowColor = 'transparent';
        ctx.globalAlpha = 1;
    }

    /**
     * Verifica se a partícula está morta
     */
    isDead() {
        return this.lifetime <= 0;
    }
}

/**
 * Gerenciador de partículas
 */
class ParticleManager {
    constructor() {
        this.particles = [];
    }

    /**
     * Cria explosão
     */
    createExplosion(x, y, count = 8, force = 3) {
        for (let i = 0; i < count; i++) {
            const angle = (i / count) * Math.PI * 2;
            const vx = Math.cos(angle) * force;
            const vy = Math.sin(angle) * force;
            const particle = new Particle(x, y, vx, vy, 40, 2);
            particle.color = '#ff6600';
            this.particles.push(particle);
        }
    }

    /**
     * Cria partículas de impacto
     */
    createImpact(x, y, count = 5) {
        for (let i = 0; i < count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const force = Math.random() * 2 + 1;
            const vx = Math.cos(angle) * force;
            const vy = Math.sin(angle) * force;
            const particle = new Particle(x, y, vx, vy, 20, 2);
            particle.color = '#ffff00';
            this.particles.push(particle);
        }
    }

    /**
     * Adiciona partícula customizada
     */
    addParticle(particle) {
        this.particles.push(particle);
    }

    /**
     * Atualiza todas as partículas
     */
    update() {
        for (let i = this.particles.length - 1; i >= 0; i--) {
            const particle = this.particles[i];
            particle.update();
            if (particle.isDead()) {
                this.particles.splice(i, 1);
            }
        }
    }

    /**
     * Desenha todas as partículas
     */
    draw(ctx) {
        this.particles.forEach(particle => particle.draw(ctx));
    }

    /**
     * Limpa todas as partículas
     */
    clear() {
        this.particles = [];
    }
}"},{"path":"js/enemies.js","content":"/**
 * GALAGA ARCADE - Inimigos
 * Sistema de inimigos com IA e padrões de ataque
 */

const EnemyTypes = {
    NORMAL: 'normal',
    STRONG: 'strong',
    BOSS: 'boss'
};

/**
 * Classe para inimigos
 */
class Enemy extends GameObject {
    constructor(x, y, type = EnemyTypes.NORMAL) {
        super(x, y, 18, 16);
        this.type = type;
        this.speed = 1;
        this.health = type === EnemyTypes.STRONG ? 2 : (type === EnemyTypes.BOSS ? 5 : 1);
        this.maxHealth = this.health;
        this.shootCooldown = 0;
        this.shootInterval = type === EnemyTypes.BOSS ? 20 : (type === EnemyTypes.STRONG ? 40 : 60);
        this.direction = 1;
        this.movePattern = 'sine'; // sine, square, line
        this.patternTime = 0;
        this.score = type === EnemyTypes.STRONG ? 25 : (type === EnemyTypes.BOSS ? 500 : 10);
    }

    /**
     * Atualiza inimigo
     */
    update(canvasWidth) {
        this.patternTime++;

        // Padrão de movimento
        switch (this.movePattern) {
            case 'sine':
                this.x += Math.sin(this.patternTime * 0.05) * this.speed;
                break;
            case 'square':
                if (this.patternTime % 60 < 30) {
                    this.x += this.speed;
                } else {
                    this.x -= this.speed;
                }
                break;
            case 'line':
                this.x += this.direction * this.speed;
                if (this.x < 0 || this.x + this.width > canvasWidth) {
                    this.direction *= -1;
                }
                break;
        }

        // Descida gradual
        this.y += 0.1;

        // Atualiza cooldown de tiro
        this.shootCooldown++;
    }

    /**
     * Tenta atirar
     */
    tryShoot(playerX) {
        if (this.shootCooldown >= this.shootInterval) {
            this.shootCooldown = 0;

            // Calcula ângulo para o jogador (para boss)
            let vx = 0;
            let vy = 3;

            if (this.type === EnemyTypes.BOSS) {
                const dx = playerX - this.x;
                const dist = Math.abs(dx) + 1;
                vx = (dx / dist) * 2;
            }

            return new Bullet(
                this.x + this.width / 2 - 2,
                this.y + this.height,
                vx,
                vy,
                false
            );
        }
        return null;
    }

    /**
     * Toma dano
     */
    takeDamage(amount = 1) {
        this.health -= amount;
        return this.health <= 0;
    }

    /**
     * Desenha inimigo
     */
    draw(ctx) {
        let color;
        if (this.type === EnemyTypes.BOSS) {
            color = '#ff6600';
        } else if (this.type === EnemyTypes.STRONG) {
            color = '#ff0080';
        } else {
            color = '#ff00ff';
        }

        ctx.fillStyle = color;
        ctx.shadowColor = color;
        ctx.shadowBlur = this.type === EnemyTypes.BOSS ? 15 : 10;

        // Desenha corpo do inimigo
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y);
        ctx.lineTo(this.x + this.width, this.y + 8);
        ctx.lineTo(this.x + this.width - 3, this.y + this.height);
        ctx.lineTo(this.x + 3, this.y + this.height);
        ctx.lineTo(this.x, this.y + 8);
        ctx.closePath();
        ctx.fill();

        // Olhos
        ctx.fillStyle = '#ffff00';
        ctx.fillRect(this.x + 5, this.y + 4, 2, 2);
        ctx.fillRect(this.x + this.width - 7, this.y + 4, 2, 2);

        // Barra de vida para boss
        if (this.type === EnemyTypes.BOSS) {
            const healthBarWidth = this.width;
            const healthBarHeight = 2;
            ctx.fillStyle = '#333';
            ctx.fillRect(this.x, this.y - 5, healthBarWidth, healthBarHeight);
            ctx.fillStyle = '#00ff00';
            const healthPercent = this.health / this.maxHealth;
            ctx.fillRect(this.x, this.y - 5, healthBarWidth * healthPercent, healthBarHeight);
        }

        ctx.shadowColor = 'transparent';
    }
}

/**
 * Gerenciador de inimigos
 */
class EnemyManager {
    constructor() {
        this.enemies = [];
        this.waveNumber = 0;
        this.spawnDelay = 0;
        this.spawnRate = 30;
    }

    /**
     * Gera nova onda de inimigos
     */
    spawnWave(level, canvasWidth, canvasHeight) {
        this.enemies = [];
        const enemyCount = 6 + Math.floor(level / 2);
        const columns = Math.min(8, enemyCount);
        const rows = Math.ceil(enemyCount / columns);
        const spacing = (canvasWidth - 80) / columns;

        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < columns; c++) {
                if (this.enemies.length >= enemyCount) break;

                const x = 40 + c * spacing;
                const y = 30 + r * 50;
                let type = EnemyTypes.NORMAL;

                // Alguns inimigos são mais fortes
                if (Math.random() < level * 0.1) {
                    type = EnemyTypes.STRONG;
                }

                const enemy = new Enemy(x, y, type);
                enemy.speed = 1 + (level - 1) * 0.3;

                this.enemies.push(enemy);
            }
        }

        // Boss a cada 5 níveis
        if (level % 5 === 0) {
            const boss = new Enemy(canvasWidth / 2 - 15, 20, EnemyTypes.BOSS);
            boss.speed = 0.5 + (level - 1) * 0.1;
            this.enemies.push(boss);
        }
    }

    /**
     * Atualiza inimigos
     */
    update(canvasWidth, canvasHeight) {
        this.enemies.forEach(enemy => {
            enemy.update(canvasWidth);
        });

        // Remove inimigos fora da tela
        this.enemies = this.enemies.filter(enemy => {
            return enemy.y < canvasHeight + 50;
        });
    }

    /**
     * Tenta disparos dos inimigos
     */
    tryShoot(playerX) {
        const bullets = [];
        this.enemies.forEach(enemy => {
            const bullet = enemy.tryShoot(playerX);
            if (bullet) bullets.push(bullet);
        });
        return bullets;
    }

    /**
     * Desenha inimigos
     */
    draw(ctx) {
        this.enemies.forEach(enemy => enemy.draw(ctx));
    }

    /**
     * Remove inimigo
     */
    removeEnemy(enemy) {
        const index = this.enemies.indexOf(enemy);
        if (index > -1) {
            this.enemies.splice(index, 1);
        }
    }

    /**
     * Verifica se todos os inimigos foram destruídos
     */
    isAllDefeated() {
        return this.enemies.length === 0;
    }

    /**
     * Obtém quantidade de inimigos
     */
    getCount() {
        return this.enemies.length;
    }

    /**
     * Limpa inimigos
     */
    clear() {
        this.enemies = [];
    }
}"},{"path":"js/game.js","content":"/**
 * GALAGA ARCADE - Motor do Jogo Principal
 * Loop de jogo e controle geral
 */

// ===========================
// CONSTANTES DO JOGO
// ===========================

const GAME_WIDTH = 800;
const GAME_HEIGHT = 600;
const PLAYER_SPEED = 5;
const BULLET_SPEED = 7;
const MAX_LEVELS = 10;

// ===========================
// CLASS GAME
// ===========================

class Game {
    constructor(canvasId = 'gameCanvas') {
        this.canvas = document.getElementById(canvasId);
        this.ctx = this.canvas.getContext('2d');

        // Objetos do jogo
        this.player = new Player(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
        this.enemies = new EnemyManager();
        this.bullets = new BulletManager();
        this.particles = new ParticleManager();
        this.gameState = new GameStateManager();

        // Controles
        this.keys = {};
        this.touchX = null;
        this.touchActive = false;

        // Sistema de som
        this.audio = initAudio();

        // Timing
        this.lastTime = Date.now();
        this.deltaTime = 0;
        this.fps = 0;
        this.frameCount = 0;

        // Estado de pausa
        this.isPaused = false;
        this.levelUpTimer = 0;
        this.levelUpDuration = 180; // 3 segundos a 60 FPS

        // Inicializa
        this.init();
    }

    /**
     * Inicializa o jogo
     */
    init() {
        this.setupEventListeners();
        this.setupTouchControls();
        this.enemies.spawnWave(this.gameState.level, GAME_WIDTH, GAME_HEIGHT);
        this.updateUI();
        this.startGameLoop();
    }

    /**
     * Configura listeners de eventos
     */
    setupEventListeners() {
        // Teclado
        document.addEventListener('keydown', (e) => {
            this.keys[e.key] = true;

            // Controles especiais
            if (e.key === ' ') {
                e.preventDefault();
                if (this.gameState.isState(GameStates.MENU)) {
                    this.startGame();
                } else if (this.gameState.isState(GameStates.GAME_OVER)) {
                    this.restart();
                }
            }

            if (e.key === 'p' || e.key === 'P') {
                this.togglePause();
            }

            if (e.key === 'r' || e.key === 'R') {
                if (this.gameState.isState(GameStates.GAME_OVER)) {
                    this.restart();
                }
            }
        });

        document.addEventListener('keyup', (e) => {
            this.keys[e.key] = false;
        });

        // Botões do menu
        const restartBtn = getElement('restartBtn');
        if (restartBtn) {
            restartBtn.addEventListener('click', () => this.restart());
        }

        // Modal de pausa
        const pauseMenu = getElement('pauseMenu');
        if (pauseMenu) {
            pauseMenu.addEventListener('click', () => {
                if (this.gameState.isState(GameStates.PAUSED)) {
                    this.togglePause();
                }
            });
        }

        // Evitar comportamento padrão
        this.canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            this.audio.resumeAudioContext();
        });
    }

    /**
     * Configura controles de toque
     */
    setupTouchControls() {
        if (!isTouchDevice()) return;

        const touchControls = getElement('touchControls');
        if (!touchControls) return;

        if (isMobileDevice()) {
            addClass(touchControls, 'visible');
            addClass(getElement('controls-desktop'), 'hidden');
            removeClass(getElement('controls-mobile'), 'hidden');
        }

        // Toque na tela para atirar
        this.canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            if (this.gameState.isState(GameStates.PLAYING)) {
                const touch = e.touches[0];
                this.touchX = touch.clientX;
                this.touchActive = true;
            }
        });

        this.canvas.addEventListener('touchmove', (e) => {
            e.preventDefault();
            if (this.gameState.isState(GameStates.PLAYING) && this.touchActive) {
                const touch = e.touches[0];
                const rect = this.canvas.getBoundingClientRect();
                const x = touch.clientX - rect.left;

                // Converte coordenada de tela para canvas
                const canvasX = (x / rect.width) * GAME_WIDTH;
                this.player.x = clamp(canvasX - this.player.width / 2, 0, GAME_WIDTH - this.player.width);
            }
        });

        this.canvas.addEventListener('touchend', (e) => {
            e.preventDefault();
            this.touchActive = false;
        });

        // Botões de toque
        const touchLeft = getElement('touchLeft');
        const touchRight = getElement('touchRight');
        const touchShoot = getElement('touchShoot');

        if (touchLeft) {
            touchLeft.addEventListener('touchstart', () => { this.keys['ArrowLeft'] = true; });
            touchLeft.addEventListener('touchend', () => { this.keys['ArrowLeft'] = false; });
        }

        if (touchRight) {
            touchRight.addEventListener('touchstart', () => { this.keys['ArrowRight'] = true; });
            touchRight.addEventListener('touchend', () => { this.keys['ArrowRight'] = false; });
        }

        if (touchShoot) {
            touchShoot.addEventListener('touchstart', (e) => {
                e.preventDefault();
                this.keys[' '] = true;
            });
            touchShoot.addEventListener('touchend', () => { this.keys[' '] = false; });
        }
    }

    /**
     * Inicia o jogo
     */
    startGame() {
        this.gameState.reset();
        this.enemies.spawnWave(this.gameState.level, GAME_WIDTH, GAME_HEIGHT);
        this.bullets.clear();
        this.particles.clear();
        this.player.reset(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
        this.updateUI();
        setText('status', `Nível ${this.gameState.level} - Prepare-se!`);
    }

    /**
     * Alterna pausa
     */
    togglePause() {
        if (this.gameState.isState(GameStates.PLAYING)) {
            this.isPaused = true;
            this.gameState.setState(GameStates.PAUSED);
            removeClass(getElement('pauseMenu'), 'hidden');
        } else if (this.gameState.isState(GameStates.PAUSED)) {
            this.isPaused = false;
            this.gameState.setState(GameStates.PLAYING);
            addClass(getElement('pauseMenu'), 'hidden');
        }
    }

    /**
     * Reinicia o jogo
     */
    restart() {
        addClass(getElement('gameOverMenu'), 'hidden');
        this.startGame();
    }

    /**
     * Atualiza UI
     */
    updateUI() {
        updateScore('score', this.gameState.score);
        updateScore('highScore', this.gameState.highScore);
        setText('level', String(this.gameState.level));
        setText('lives', String(this.gameState.lives));
    }

    /**
     * Loop de atualização
     */
    update() {
        if (!this.gameState.isState(GameStates.PLAYING)) {
            return;
        }

        // Atualiza jogador
        this.player.update(this.keys, this.canvas);

        // Jogador atira
        if (this.keys[' ']) {
            const bullet = this.player.shoot();
            if (bullet) {
                this.bullets.addPlayerBullet(bullet);
            }
        }

        // Atualiza inimigos
        this.enemies.update(GAME_WIDTH, GAME_HEIGHT);

        // Inimigos atiram
        const enemyBullets = this.enemies.tryShoot(this.player.x);
        enemyBullets.forEach(bullet => this.bullets.addEnemyBullet(bullet));

        // Atualiza projéteis
        this.bullets.update(GAME_WIDTH, GAME_HEIGHT);

        // Atualiza partículas
        this.particles.update();

        // Colisões: projéteis do jogador vs inimigos
        this.checkPlayerBulletCollisions();

        // Colisões: projéteis dos inimigos vs jogador
        this.checkEnemyBulletCollisions();

        // Colisões: inimigos vs jogador
        this.checkEnemyPlayerCollisions();

        // Verifica fim de nível
        if (this.enemies.isAllDefeated()) {
            this.nextLevel();
        }

        // Verifica game over
        if (this.gameState.lives <= 0) {
            this.gameOver();
        }
    }

    /**
     * Verifica colisões dos projéteis do jogador
     */
    checkPlayerBulletCollisions() {
        for (let i = this.bullets.playerBullets.length - 1; i >= 0; i--) {
            const bullet = this.bullets.playerBullets[i];
            let hit = false;

            for (let j = this.enemies.enemies.length - 1; j >= 0; j--) {
                const enemy = this.enemies.enemies[j];
                if (checkCollision(bullet.getRect(), enemy.getRect())) {
                    hit = true;

                    if (enemy.takeDamage(bullet.damage)) {
                        // Inimigo destruído
                        this.gameState.addScore(enemy.score * this.gameState.getDifficultyMultiplier());
                        this.particles.createExplosion(enemy.x + enemy.width / 2, enemy.y + enemy.height / 2);
                        this.audio.playExplosion();
                        this.enemies.removeEnemy(enemy);
                    } else {
                        // Inimigo ferido
                        this.particles.createImpact(enemy.x + enemy.width / 2, enemy.y);
                    }
                    break;
                }
            }

            if (hit) {
                this.bullets.playerBullets.splice(i, 1);
            }
        }
    }

    /**
     * Verifica colisões dos projéteis dos inimigos
     */
    checkEnemyBulletCollisions() {
        for (let i = this.bullets.enemyBullets.length - 1; i >= 0; i--) {
            const bullet = this.bullets.enemyBullets[i];
            if (checkCollision(bullet.getRect(), this.player.getRect())) {
                if (this.player.takeDamage(1)) {
                    if (!this.gameState.loseLife()) {
                        this.gameOver();
                    } else {
                        this.player.reset(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
                    }
                }
                this.particles.createExplosion(this.player.x + this.player.width / 2, this.player.y);
                this.bullets.enemyBullets.splice(i, 1);
            }
        }
    }

    /**
     * Verifica colisões dos inimigos com o jogador
     */
    checkEnemyPlayerCollisions() {
        for (let i = this.enemies.enemies.length - 1; i >= 0; i--) {
            const enemy = this.enemies.enemies[i];
            if (checkCollision(enemy.getRect(), this.player.getRect())) {
                if (!this.player.invincible) {
                    if (this.player.takeDamage(1)) {
                        if (!this.gameState.loseLife()) {
                            this.gameOver();
                        } else {
                            this.player.reset(GAME_WIDTH / 2 - 10, GAME_HEIGHT - 60);
                        }
                    }
                    this.particles.createExplosion(this.player.x + this.player.width / 2, this.player.y);
                }
            }
        }
    }

    /**
     * Próximo nível
     */
    nextLevel() {
        this.gameState.nextLevel();
        this.levelUpTimer = this.levelUpDuration;
        setText('status', `🎉 NÍVEL ${this.gameState.level - 1} COMPLETO! 🎉`);
        this.audio.playLevelUp();
    }

    /**
     * Game over
     */
    gameOver() {
        this.gameState.setState(GameStates.GAME_OVER);
        setText('finalScore', String(this.gameState.score).padStart(6, '0'));

        if (this.gameState.isNewRecord) {
            removeClass(getElement('newRecord'), 'hidden');
        } else {
            addClass(getElement('newRecord'), 'hidden');
        }

        removeClass(getElement('gameOverMenu'), 'hidden');
        setText('status', 'GAME OVER');
        this.audio.playGameOver();
    }

    /**
     * Loop de renderização
     */
    draw() {
        // Limpa canvas
        this.ctx.fillStyle = '#000000';
        this.ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

        // Grade de fundo (efeito retrô)
        this.ctx.strokeStyle = 'rgba(0, 255, 0, 0.03)';
        this.ctx.lineWidth = 1;
        for (let i = 0; i < GAME_WIDTH; i += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(i, 0);
            this.ctx.lineTo(i, GAME_HEIGHT);
            this.ctx.stroke();
        }
        for (let i = 0; i < GAME_HEIGHT; i += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, i);
            this.ctx.lineTo(GAME_WIDTH, i);
            this.ctx.stroke();
        }

        // Desenha objetos
        this.player.draw(this.ctx);
        this.enemies.draw(this.ctx);
        this.bullets.draw(this.ctx);
        this.particles.draw(this.ctx);

        // Texto da transição de nível
        if (this.levelUpTimer > 0) {
            this.levelUpTimer--;
            const alpha = Math.min(1, Math.max(0, (this.levelUpDuration - this.levelUpTimer) / 20));
            this.ctx.globalAlpha = alpha;
            this.ctx.fillStyle = '#ffff00';
            this.ctx.font = 'bold 30px Arial';
            this.ctx.textAlign = 'center';
            this.ctx.shadowColor = 'rgba(255, 255, 0, 0.8)';
            this.ctx.shadowBlur = 20;
            this.ctx.fillText('PRÓXIMO NÍVEL!', GAME_WIDTH / 2, GAME_HEIGHT / 2);
            this.ctx.globalAlpha = 1;
            this.ctx.shadowColor = 'transparent';

            if (this.levelUpTimer === 0) {
                this.enemies.spawnWave(this.gameState.level, GAME_WIDTH, GAME_HEIGHT);
                this.bullets.clear();
                this.gameState.setState(GameStates.PLAYING);
            }
        }
    }

    /**
     * Inicia o loop do jogo
     */
    startGameLoop() {
        const gameLoop = () => {
            const currentTime = Date.now();
            this.deltaTime = Math.min((currentTime - this.lastTime) / 16.67, 2); // Máximo 2 frames
            this.lastTime = currentTime;

            // Atualiza
            if (!this.isPaused && !this.gameState.isState(GameStates.PAUSED)) {
                this.update();
            }

            // Desenha
            this.draw();

            // Atualiza UI
            this.updateUI();

            // Próximo frame
            requestAnimationFrame(gameLoop);
        };

        requestAnimationFrame(gameLoop);
    }
}

// ===========================
// INICIALIZAÇÃO
// ===========================

let game = null;

document.addEventListener('DOMContentLoaded', () => {
    // Inicializa o jogo
    game = new Game('gameCanvas');

    // Atualiza status inicial
    setText('status', 'Pressione ESPAÇO para começar');

    // Resume audio context on first interaction
    document.addEventListener('click', () => {
        if (audioManager) {
            audioManager.resumeAudioContext();
        }
    }, { once: true });
