<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <meta name="description" content="Aplicação de Lista de Tarefas com Armazenamento Local">
    <meta name="theme-color" content="#667eea">
    <title>📋 My Tasks - To-Do List</title>
    <link rel="stylesheet" href="styles/style.css">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
</head>
<body>
    <div class="container">
        <!-- Header -->
        <header class="header">
            <div class="header-content">
                <h1 class="app-title"><i class="fas fa-tasks"></i> My Tasks</h1>
                <p class="app-subtitle">Gerencie suas tarefas com facilidade</p>
            </div>
        </header>

        <!-- Main Content -->
        <main class="main-content">
            <!-- Input Section -->
            <section class="input-section">
                <div class="input-wrapper">
                    <input 
                        type="text" 
                        id="taskInput" 
                        class="task-input" 
                        placeholder="Adicione uma nova tarefa..."
                        autocomplete="off"
                    >
                    <button id="addBtn" class="btn btn-primary">
                        <i class="fas fa-plus"></i> Adicionar
                    </button>
                </div>
                <div class="input-options">
                    <select id="categorySelect" class="category-select">
                        <option value="all">Todas as Categorias</option>
                        <option value="trabalho">💼 Trabalho</option>
                        <option value="pessoal">👤 Pessoal</option>
                        <option value="compras">🛒 Compras</option>
                        <option value="saude">🏥 Saúde</option>
                        <option value="outros">📌 Outros</option>
                    </select>
                </div>
            </section>

            <!-- Stats Section -->
            <section class="stats-section">
                <div class="stat-card">
                    <div class="stat-icon" style="background: #667eea;">
                        <i class="fas fa-tasks"></i>
                    </div>
                    <div class="stat-content">
                        <span class="stat-label">Total</span>
                        <span class="stat-value" id="totalTasks">0</span>
                    </div>
                </div>
                <div class="stat-card">
                    <div class="stat-icon" style="background: #48bb78;">
                        <i class="fas fa-check-circle"></i>
                    </div>
                    <div class="stat-content">
                        <span class="stat-label">Concluídas</span>
                        <span class="stat-value" id="completedTasks">0</span>
                    </div>
                </div>
                <div class="stat-card">
                    <div class="stat-icon" style="background: #f6ad55;">
                        <i class="fas fa-hourglass-half"></i>
                    </div>
                    <div class="stat-content">
                        <span class="stat-label">Pendentes</span>
                        <span class="stat-value" id="pendingTasks">0</span>
                    </div>
                </div>
            </section>

            <!-- Filter Section -->
            <section class="filter-section">
                <button class="filter-btn active" data-filter="all">
                    <i class="fas fa-list"></i> Todas
                </button>
                <button class="filter-btn" data-filter="pending">
                    <i class="fas fa-circle"></i> Pendentes
                </button>
                <button class="filter-btn" data-filter="completed">
                    <i class="fas fa-check-circle"></i> Concluídas
                </button>
                <button class="filter-btn" data-filter="important">
                    <i class="fas fa-star"></i> Importantes
                </button>
            </section>

            <!-- Tasks Section -->
            <section class="tasks-section">
                <div class="tasks-list" id="tasksList">
                    <!-- Tasks will be inserted here -->
                </div>
                <div class="empty-state hidden" id="emptyState">
                    <i class="fas fa-check-double"></i>
                    <h2>Nenhuma tarefa encontrada</h2>
                    <p>Adicione uma nova tarefa para começar!</p>
                </div>
            </section>
        </main>

        <!-- Footer -->
        <footer class="footer">
            <div class="footer-content">
                <button id="clearCompleted" class="btn btn-secondary">
                    <i class="fas fa-trash"></i> Limpar Concluídas
                </button>
                <button id="exportBtn" class="btn btn-secondary">
                    <i class="fas fa-download"></i> Exportar
                </button>
                <button id="settingsBtn" class="btn btn-secondary">
                    <i class="fas fa-cog"></i> Configurações
                </button>
            </div>
        </footer>
    </div>

    <!-- Edit Modal -->
    <div id="editModal" class="modal hidden">
        <div class="modal-content">
            <div class="modal-header">
                <h2>Editar Tarefa</h2>
                <button class="modal-close" id="closeEditModal">
                    <i class="fas fa-times"></i>
                </button>
            </div>
            <div class="modal-body">
                <input 
                    type="text" 
                    id="editTaskInput" 
                    class="task-input" 
                    placeholder="Descrição da tarefa"
                >
                <select id="editCategorySelect" class="category-select">
                    <option value="trabalho">💼 Trabalho</option>
                    <option value="pessoal">👤 Pessoal</option>
                    <option value="compras">🛒 Compras</option>
                    <option value="saude">🏥 Saúde</option>
                    <option value="outros">📌 Outros</option>
                </select>
                <div class="priority-selector">
                    <label class="priority-option">
                        <input type="radio" name="priority" value="low" checked>
                        <span class="priority-label low">Baixa</span>
                    </label>
                    <label class="priority-option">
                        <input type="radio" name="priority" value="medium">
                        <span class="priority-label medium">Média</span>
                    </label>
                    <label class="priority-option">
                        <input type="radio" name="priority" value="high">
                        <span class="priority-label high">Alta</span>
                    </label>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" id="cancelEditBtn">Cancelar</button>
                <button class="btn btn-primary" id="saveEditBtn">Salvar Alterações</button>
            </div>
        </div>
    </div>

    <!-- Settings Modal -->
    <div id="settingsModal" class="modal hidden">
        <div class="modal-content">
            <div class="modal-header">
                <h2>Configurações</h2>
                <button class="modal-close" id="closeSettingsModal">
                    <i class="fas fa-times"></i>
                </button>
            </div>
            <div class="modal-body">
                <div class="settings-group">
                    <label class="setting-item">
                        <input type="checkbox" id="soundToggle" checked>
                        <span>Som ativado</span>
                    </label>
                </div>
                <div class="settings-group">
                    <label class="setting-item">
                        <input type="checkbox" id="notificationToggle" checked>
                        <span>Notificações ativadas</span>
                    </label>
                </div>
                <div class="settings-group">
                    <label class="setting-item">
                        <input type="checkbox" id="darkModeToggle">
                        <span>Modo escuro</span>
                    </label>
                </div>
                <div class="settings-group">
                    <button class="btn btn-danger" id="clearAllBtn">
                        <i class="fas fa-trash"></i> Limpar Todas as Tarefas
                    </button>
                </div>
            </div>
        </div>
    </div>

    <!-- Toast Notification -->
    <div id="toast" class="toast hidden"></div>

    <!-- Scripts -->
    <script src="js/storage.js"></script>
    <script src="js/ui.js"></script>
    <script src="js/app.js"></script>
</body>
</html>","path":"index.html"},{"content":"/* =============================================
   MY TASKS - TO-DO LIST
   Estilos Principais
   ============================================= */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --primary-color: #667eea;
    --secondary-color: #764ba2;
    --success-color: #48bb78;
    --warning-color: #f6ad55;
    --danger-color: #f56565;
    --dark-bg: #1a202c;
    --light-bg: #f7fafc;
    --white: #ffffff;
    --text-dark: #2d3748;
    --text-light: #718096;
    --border-color: #e2e8f0;
    --shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
    --shadow-lg: 0 10px 15px rgba(0, 0, 0, 0.1);
}

body.dark-mode {
    --primary-color: #667eea;
    --dark-bg: #0f1419;
    --light-bg: #1a202c;
    --white: #2d3748;
    --text-dark: #e2e8f0;
    --text-light: #cbd5e0;
    --border-color: #2d3748;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: var(--text-dark);
    line-height: 1.6;
    min-height: 100vh;
    transition: background 0.3s ease;
}

body.dark-mode {
    background: linear-gradient(135deg, #0f1419 0%, #1a202c 100%);
}

.container {
    max-width: 900px;
    margin: 0 auto;
    padding: 20px;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

/* =============================================
   HEADER
   ============================================= */

.header {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 15px;
    padding: 40px 30px;
    margin-bottom: 30px;
    box-shadow: var(--shadow-lg);
    text-align: center;
}

body.dark-mode .header {
    background: rgba(45, 55, 72, 0.95);
}

.app-title {
    font-size: 2.5rem;
    font-weight: 700;
    color: var(--primary-color);
    margin-bottom: 10px;
}

.app-subtitle {
    font-size: 1rem;
    color: var(--text-light);
}

/* =============================================
   INPUT SECTION
   ============================================= */

.input-section {
    background: var(--white);
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 25px;
    box-shadow: var(--shadow);
}

body.dark-mode .input-section {
    background: var(--light-bg);
}

.input-wrapper {
    display: flex;
    gap: 10px;
    margin-bottom: 15px;
}

.task-input {
    flex: 1;
    padding: 12px 16px;
    border: 2px solid var(--border-color);
    border-radius: 8px;
    font-size: 1rem;
    transition: all 0.3s ease;
    background: var(--white);
    color: var(--text-dark);
}

body.dark-mode .task-input {
    background: rgba(255, 255, 255, 0.05);
    color: var(--text-dark);
    border-color: var(--border-color);
}

.task-input:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
}

.input-options {
    display: flex;
    gap: 10px;
}

.category-select {
    padding: 10px 12px;
    border: 2px solid var(--border-color);
    border-radius: 8px;
    background: var(--white);
    color: var(--text-dark);
    font-size: 0.9rem;
    cursor: pointer;
    transition: all 0.3s ease;
}

body.dark-mode .category-select {
    background: rgba(255, 255, 255, 0.05);
    color: var(--text-dark);
}

.category-select:focus {
    outline: none;
    border-color: var(--primary-color);
}

/* =============================================
   BUTTONS
   ============================================= */

.btn {
    padding: 12px 24px;
    border: none;
    border-radius: 8px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    white-space: nowrap;
}

.btn-primary {
    background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
    color: white;
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-lg);
}

.btn-primary:active {
    transform: translateY(0);
}

.btn-secondary {
    background: var(--light-bg);
    color: var(--text-dark);
    border: 1px solid var(--border-color);
}

.btn-secondary:hover {
    background: var(--border-color);
}

.btn-danger {
    background: var(--danger-color);
    color: white;
}

.btn-danger:hover {
    opacity: 0.9;
}

/* =============================================
   STATS SECTION
   ============================================= */

.stats-section {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
    margin-bottom: 25px;
}

.stat-card {
    background: var(--white);
    border-radius: 12px;
    padding: 20px;
    display: flex;
    align-items: center;
    gap: 15px;
    box-shadow: var(--shadow);
}

body.dark-mode .stat-card {
    background: var(--light-bg);
}

.stat-icon {
    width: 50px;
    height: 50px;
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: white;
    font-size: 1.5rem;
}

.stat-content {
    display: flex;
    flex-direction: column;
}

.stat-label {
    font-size: 0.85rem;
    color: var(--text-light);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.stat-value {
    font-size: 1.8rem;
    font-weight: 700;
    color: var(--primary-color);
}

/* =============================================
   FILTER SECTION
   ============================================= */

.filter-section {
    display: flex;
    gap: 10px;
    margin-bottom: 25px;
    flex-wrap: wrap;
}

.filter-btn {
    padding: 10px 16px;
    border: 2px solid var(--border-color);
    background: var(--white);
    color: var(--text-dark);
    border-radius: 8px;
    cursor: pointer;
    font-weight: 600;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    gap: 6px;
}

body.dark-mode .filter-btn {
    background: var(--light-bg);
}

.filter-btn:hover {
    border-color: var(--primary-color);
    color: var(--primary-color);
}

.filter-btn.active {
    background: var(--primary-color);
    color: white;
    border-color: var(--primary-color);
}

/* =============================================
   TASKS SECTION
   ============================================= */

.tasks-section {
    background: var(--white);
    border-radius: 15px;
    padding: 25px;
    box-shadow: var(--shadow);
    flex: 1;
}

body.dark-mode .tasks-section {
    background: var(--light-bg);
}

.tasks-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

/* =============================================
   TASK ITEM
   ============================================= */

.task-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 15px;
    background: var(--light-bg);
    border-radius: 10px;
    transition: all 0.3s ease;
    border-left: 4px solid transparent;
}

body.dark-mode .task-item {
    background: rgba(255, 255, 255, 0.05);
}

.task-item:hover {
    transform: translateX(5px);
    box-shadow: var(--shadow);
}

.task-item.completed {
    opacity: 0.6;
}

.task-item.completed .task-text {
    text-decoration: line-through;
    color: var(--text-light);
}

.task-priority-low {
    border-left-color: #48bb78;
}

.task-priority-medium {
    border-left-color: #f6ad55;
}

.task-priority-high {
    border-left-color: #f56565;
}

.task-checkbox {
    width: 20px;
    height: 20px;
    cursor: pointer;
    accent-color: var(--success-color);
}

.task-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.task-text {
    font-weight: 500;
    color: var(--text-dark);
}

.task-meta {
    display: flex;
    gap: 12px;
    font-size: 0.85rem;
}

.task-category {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 4px 8px;
    background: rgba(102, 126, 234, 0.1);
    border-radius: 4px;
    color: var(--primary-color);
}

.task-date {
    color: var(--text-light);
}

.task-actions {
    display: flex;
    gap: 8px;
}

.action-btn {
    width: 36px;
    height: 36px;
    border: none;
    background: rgba(102, 126, 234, 0.1);
    color: var(--primary-color);
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    justify-content: center;
}

.action-btn:hover {
    background: var(--primary-color);
    color: white;
    transform: scale(1.1);
}

.action-btn.delete:hover {
    background: var(--danger-color);
}

.action-btn.important:hover {
    background: var(--warning-color);
}

.action-btn.important.starred {
    background: var(--warning-color);
    color: white;
}

/* =============================================
   EMPTY STATE
   ============================================= */

.empty-state {
    text-align: center;
    padding: 60px 30px;
    color: var(--text-light);
}

.empty-state.hidden {
    display: none;
}

.empty-state i {
    font-size: 4rem;
    margin-bottom: 20px;
    opacity: 0.5;
}

.empty-state h2 {
    font-size: 1.5rem;
    margin-bottom: 10px;
    color: var(--text-dark);
}

/* =============================================
   FOOTER
   ============================================= */

.footer {
    margin-top: 30px;
    padding-top: 20px;
    border-top: 1px solid var(--border-color);
}

.footer-content {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
}

/* =============================================
   MODAL
   ============================================= */

.modal {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal.hidden {
    display: none;
}

.modal-content {
    background: var(--white);
    border-radius: 15px;
    width: 90%;
    max-width: 500px;
    box-shadow: var(--shadow-lg);
    animation: slideUp 0.3s ease;
}

body.dark-mode .modal-content {
    background: var(--light-bg);
}

@keyframes slideUp {
    from {
        transform: translateY(20px);
        opacity: 0;
    }
    to {
        transform: translateY(0);
        opacity: 1;
    }
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px;
    border-bottom: 1px solid var(--border-color);
}

.modal-header h2 {
    font-size: 1.5rem;
    color: var(--text-dark);
}

.modal-close {
    background: none;
    border: none;
    font-size: 1.5rem;
    color: var(--text-light);
    cursor: pointer;
    transition: color 0.3s ease;
}

.modal-close:hover {
    color: var(--text-dark);
}

.modal-body {
    padding: 20px;
    display: flex;
    flex-direction: column;
    gap: 15px;
}

.modal-footer {
    display: flex;
    gap: 10px;
    padding: 20px;
    border-top: 1px solid var(--border-color);
}

.modal-footer .btn {
    flex: 1;
}

/* =============================================
   PRIORITY SELECTOR
   ============================================= */

.priority-selector {
    display: flex;
    gap: 10px;
}

.priority-option {
    flex: 1;
    position: relative;
}

.priority-option input {
    display: none;
}

.priority-label {
    display: block;
    padding: 10px;
    border: 2px solid var(--border-color);
    border-radius: 8px;
    text-align: center;
    cursor: pointer;
    transition: all 0.3s ease;
    font-weight: 600;
}

.priority-label.low {
    color: var(--success-color);
}

.priority-label.medium {
    color: var(--warning-color);
}

.priority-label.high {
    color: var(--danger-color);
}

.priority-option input:checked + .priority-label {
    border-color: var(--primary-color);
    background: rgba(102, 126, 234, 0.1);
}

/* =============================================
   SETTINGS
   ============================================= */

.settings-group {
    padding: 15px 0;
    border-bottom: 1px solid var(--border-color);
}

.settings-group:last-child {
    border-bottom: none;
}

.setting-item {
    display: flex;
    align-items: center;
    gap: 10px;
    cursor: pointer;
    font-weight: 500;
    color: var(--text-dark);
}

.setting-item input[type="checkbox"] {
    width: 18px;
    height: 18px;
    cursor: pointer;
    accent-color: var(--primary-color);
}

/* =============================================
   TOAST
   ============================================= */

.toast {
    position: fixed;
    bottom: 20px;
    right: 20px;
    background: var(--text-dark);
    color: white;
    padding: 15px 20px;
    border-radius: 8px;
    box-shadow: var(--shadow-lg);
    animation: slideInRight 0.3s ease;
    z-index: 2000;
}

.toast.hidden {
    display: none;
}

.toast.success {
    background: var(--success-color);
}

.toast.error {
    background: var(--danger-color);
}

.toast.warning {
    background: var(--warning-color);
}

@keyframes slideInRight {
    from {
        transform: translateX(400px);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}

/* =============================================
   RESPONSIVE DESIGN
   ============================================= */

@media (max-width: 768px) {
    .container {
        padding: 10px;
    }

    .header {
        padding: 20px 15px;
        margin-bottom: 15px;
    }

    .app-title {
        font-size: 1.8rem;
    }

    .input-wrapper {
        flex-direction: column;
    }

    .input-options {
        flex-direction: column;
    }

    .stats-section {
        grid-template-columns: 1fr;
    }

    .filter-section {
        gap: 8px;
    }

    .filter-btn {
        flex: 1;
        font-size: 0.85rem;
        padding: 8px 12px;
    }

    .task-item {
        flex-direction: column;
        align-items: flex-start;
    }

    .task-actions {
        width: 100%;
        justify-content: flex-end;
    }

    .footer-content {
        flex-direction: column;
    }

    .footer-content .btn {
        width: 100%;
    }

    .modal-content {
        width: 95%;
    }
}

@media (max-width: 480px) {
    .app-title {
        font-size: 1.5rem;
    }

    .stat-card {
        padding: 15px;
    }

    .stat-value {
        font-size: 1.5rem;
    }

    .task-input,
    .category-select {
        font-size: 16px; /* Prevent zoom on iOS */
    }
}
","path":"styles/style.css"},{"content":"/**
 * MY TASKS - Storage Manager
 * Gerencia armazenamento local de tarefas
 */

class TaskStorage {
    constructor() {
        this.storageKey = 'myTasks';
        this.settingsKey = 'myTasksSettings';
    }

    /**
     * Obtém todas as tarefas do localStorage
     */
    getAllTasks() {
        try {
            const tasks = localStorage.getItem(this.storageKey);
            return tasks ? JSON.parse(tasks) : [];
        } catch (error) {
            console.error('Erro ao obter tarefas:', error);
            return [];
        }
    }

    /**
     * Salva todas as tarefas no localStorage
     */
    saveTasks(tasks) {
        try {
            localStorage.setItem(this.storageKey, JSON.stringify(tasks));
            return true;
        } catch (error) {
            console.error('Erro ao salvar tarefas:', error);
            return false;
        }
    }

    /**
     * Adiciona uma nova tarefa
     */
    addTask(task) {
        const tasks = this.getAllTasks();
        const newTask = {
            id: Date.now(),
            text: task.text,
            category: task.category || 'outros',
            priority: task.priority || 'low',
            completed: false,
            important: false,
            createdAt: new Date().toISOString(),
            dueDate: task.dueDate || null
        };
        tasks.push(newTask);
        this.saveTasks(tasks);
        return newTask;
    }

    /**
     * Atualiza uma tarefa
     */
    updateTask(id, updates) {
        const tasks = this.getAllTasks();
        const taskIndex = tasks.findIndex(t => t.id === id);

        if (taskIndex !== -1) {
            tasks[taskIndex] = { ...tasks[taskIndex], ...updates };
            this.saveTasks(tasks);
            return tasks[taskIndex];
        }
        return null;
    }

    /**
     * Deleta uma tarefa
     */
    deleteTask(id) {
        const tasks = this.getAllTasks();
        const filteredTasks = tasks.filter(t => t.id !== id);
        this.saveTasks(filteredTasks);
        return filteredTasks.length < tasks.length;
    }

    /**
     * Limpa todas as tarefas concluídas
     */
    clearCompleted() {
        const tasks = this.getAllTasks();
        const activeTasks = tasks.filter(t => !t.completed);
        const cleared = tasks.length - activeTasks.length;
        this.saveTasks(activeTasks);
        return cleared;
    }

    /**
     * Limpa todas as tarefas
     */
    clearAll() {
        this.saveTasks([]);
    }

    /**
     * Obtém tarefas filtradas
     */
    getFilteredTasks(filter) {
        const tasks = this.getAllTasks();

        switch (filter) {
            case 'completed':
                return tasks.filter(t => t.completed);
            case 'pending':
                return tasks.filter(t => !t.completed);
            case 'important':
                return tasks.filter(t => t.important);
            default:
                return tasks;
        }
    }

    /**
     * Obtém tarefas por categoria
     */
    getTasksByCategory(category) {
        const tasks = this.getAllTasks();
        if (category === 'all') return tasks;
        return tasks.filter(t => t.category === category);
    }

    /**
     * Obtém estatísticas das tarefas
     */
    getStats() {
        const tasks = this.getAllTasks();
        const completed = tasks.filter(t => t.completed).length;
        const pending = tasks.length - completed;

        return {
            total: tasks.length,
            completed,
            pending,
            percentage: tasks.length > 0 ? Math.round((completed / tasks.length) * 100) : 0
        };
    }

    /**
     * Obtém configurações
     */
    getSettings() {
        try {
            const settings = localStorage.getItem(this.settingsKey);
            return settings ? JSON.parse(settings) : this.getDefaultSettings();
        } catch (error) {
            return this.getDefaultSettings();
        }
    }

    /**
     * Salva configurações
     */
    saveSettings(settings) {
        try {
            localStorage.setItem(this.settingsKey, JSON.stringify(settings));
            return true;
        } catch (error) {
            console.error('Erro ao salvar configurações:', error);
            return false;
        }
    }

    /**
     * Configurações padrão
     */
    getDefaultSettings() {
        return {
            sound: true,
            notifications: true,
            darkMode: false,
            theme: 'light'
        };
    }

    /**
     * Exporta tarefas como JSON
     */
    exportTasks() {
        const tasks = this.getAllTasks();
        const stats = this.getStats();
        const data = {
            tasks,
            stats,
            exportedAt: new Date().toISOString()
        };
        return JSON.stringify(data, null, 2);
    }

    /**
     * Importa tarefas de um arquivo JSON
     */
    importTasks(jsonData) {
        try {
            const data = JSON.parse(jsonData);
            if (Array.isArray(data.tasks)) {
                this.saveTasks(data.tasks);
                return true;
            }
            return false;
        } catch (error) {
            console.error('Erro ao importar tarefas:', error);
            return false;
        }
    }
}

