","path":"js/storage.js"},{"content":"/**
 * MY TASKS - UI Manager
 * Gerencia a interface do usuário
 */

class TaskUI {
    constructor() {
        this.currentFilter = 'all';
        this.currentCategory = 'all';
        this.editingTaskId = null;
    }

    /**
     * Renderiza a lista de tarefas
     */
    renderTasks(tasks) {
        const tasksList = document.getElementById('tasksList');
        const emptyState = document.getElementById('emptyState');

        if (tasks.length === 0) {
            tasksList.innerHTML = '';
            emptyState.classList.remove('hidden');
            return;
        }

        emptyState.classList.add('hidden');
        tasksList.innerHTML = tasks.map(task => this.createTaskElement(task)).join('');
        this.attachTaskListeners();
    }

    /**
     * Cria um elemento de tarefa
     */
    createTaskElement(task) {
        const date = new Date(task.createdAt).toLocaleDateString('pt-BR');
        const categoryEmoji = this.getCategoryEmoji(task.category);
        const priorityClass = `task-priority-${task.priority}`;
        const completedClass = task.completed ? 'completed' : '';

        return `
            <div class="task-item ${completedClass} ${priorityClass}" data-id="${task.id}">
                <input 
                    type="checkbox" 
                    class="task-checkbox" 
                    ${task.completed ? 'checked' : ''}
                    data-id="${task.id}"
                >
                <div class="task-content">
                    <span class="task-text">${this.escapeHtml(task.text)}</span>
                    <div class="task-meta">
                        <span class="task-category">${categoryEmoji} ${this.getCategoryLabel(task.category)}</span>
                        <span class="task-date">📅 ${date}</span>
                    </div>
                </div>
                <div class="task-actions">
                    <button class="action-btn important ${task.important ? 'starred' : ''}" data-id="${task.id}" title="Marcar como importante">
                        <i class="fas fa-star"></i>
                    </button>
                    <button class="action-btn edit" data-id="${task.id}" title="Editar tarefa">
                        <i class="fas fa-edit"></i>
                    </button>
                    <button class="action-btn delete" data-id="${task.id}" title="Deletar tarefa">
                        <i class="fas fa-trash"></i>
                    </button>
                </div>
            </div>
        `;
    }

    /**
     * Obtém emoji da categoria
     */
    getCategoryEmoji(category) {
        const emojis = {
            'trabalho': '💼',
            'pessoal': '👤',
            'compras': '🛒',
            'saude': '🏥',
            'outros': '📌'
        };
        return emojis[category] || '📌';
    }

    /**
     * Obtém rótulo da categoria
     */
    getCategoryLabel(category) {
        const labels = {
            'trabalho': 'Trabalho',
            'pessoal': 'Pessoal',
            'compras': 'Compras',
            'saude': 'Saúde',
            'outros': 'Outros'
        };
        return labels[category] || 'Outros';
    }

    /**
     * Atualiza estatísticas
     */
    updateStats() {
        const stats = taskStorage.getStats();
        document.getElementById('totalTasks').textContent = stats.total;
        document.getElementById('completedTasks').textContent = stats.completed;
        document.getElementById('pendingTasks').textContent = stats.pending;
    }

    /**
     * Mostra notificação (toast)
     */
    showToast(message, type = 'success') {
        const toast = document.getElementById('toast');
        toast.textContent = message;
        toast.className = `toast ${type}`;
        toast.classList.remove('hidden');

        setTimeout(() => {
            toast.classList.add('hidden');
        }, 3000);
    }

    /**
     * Abre modal de edição
     */
    openEditModal(task) {
        this.editingTaskId = task.id;
        document.getElementById('editTaskInput').value = task.text;
        document.getElementById('editCategorySelect').value = task.category;
        document.querySelector(`input[name="priority"][value="${task.priority}"]`).checked = true;
        document.getElementById('editModal').classList.remove('hidden');
    }

    /**
     * Fecha modal de edição
     */
    closeEditModal() {
        document.getElementById('editModal').classList.add('hidden');
        this.editingTaskId = null;
    }

    /**
     * Obtém dados do modal de edição
     */
    getEditModalData() {
        return {
            text: document.getElementById('editTaskInput').value,
            category: document.getElementById('editCategorySelect').value,
            priority: document.querySelector('input[name="priority"]:checked').value
        };
    }

    /**
     * Abre modal de configurações
     */
    openSettingsModal() {
        const settings = taskStorage.getSettings();
        document.getElementById('soundToggle').checked = settings.sound;
        document.getElementById('notificationToggle').checked = settings.notifications;
        document.getElementById('darkModeToggle').checked = settings.darkMode;
        document.getElementById('settingsModal').classList.remove('hidden');
    }

    /**
     * Fecha modal de configurações
     */
    closeSettingsModal() {
        document.getElementById('settingsModal').classList.add('hidden');
    }

    /**
     * Obtém configurações do modal
     */
    getSettingsModalData() {
        return {
            sound: document.getElementById('soundToggle').checked,
            notifications: document.getElementById('notificationToggle').checked,
            darkMode: document.getElementById('darkModeToggle').checked
        };
    }

    /**
     * Ativa modo escuro
     */
    toggleDarkMode(enabled) {
        if (enabled) {
            document.body.classList.add('dark-mode');
        } else {
            document.body.classList.remove('dark-mode');
        }
    }

    /**
     * Escapa caracteres HTML
     */
    escapeHtml(text) {
        const map = {
            '&': '&amp;',
            '<': '&lt;',
            '>': '&gt;',
            '"': '&quot;',
            "'": '&#039;'
        };
        return text.replace(/[&<>"']/g, m => map[m]);
    }

    /**
     * Formata data
     */
    formatDate(date) {
        return new Date(date).toLocaleDateString('pt-BR');
    }

    /**
     * Reproduz som
     */
    playSound(type = 'click') {
        const settings = taskStorage.getSettings();
        if (!settings.sound) return;

        const audioContext = new (window.AudioContext || window.webkitAudioContext)();
        const oscillator = audioContext.createOscillator();
        const gainNode = audioContext.createGain();

        oscillator.connect(gainNode);
        gainNode.connect(audioContext.destination);

        switch (type) {
            case 'complete':
                oscillator.frequency.value = 800;
                gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
                gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.1);
                oscillator.start(audioContext.currentTime);
                oscillator.stop(audioContext.currentTime + 0.1);
                break;
            case 'delete':
                oscillator.frequency.value = 300;
                gainNode.gain.setValueAtTime(0.2, audioContext.currentTime);
                gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.15);
                oscillator.start(audioContext.currentTime);
                oscillator.stop(audioContext.currentTime + 0.15);
                break;
            default:
                oscillator.frequency.value = 600;
                gainNode.gain.setValueAtTime(0.1, audioContext.currentTime);
                gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.05);
                oscillator.start(audioContext.currentTime);
                oscillator.stop(audioContext.currentTime + 0.05);
        }
    }

    /**
     * Anexa listeners aos botões de tarefas
     */
    attachTaskListeners() {
        // Checkboxes
        document.querySelectorAll('.task-checkbox').forEach(checkbox => {
            checkbox.addEventListener('change', (e) => {
                const id = parseInt(e.target.dataset.id);
                const task = taskStorage.getAllTasks().find(t => t.id === id);
                taskStorage.updateTask(id, { completed: e.target.checked });
                this.updateStats();
                this.refreshTasks();
                this.playSound(task.completed ? 'complete' : 'click');
            });
        });

        // Botões de edição
        document.querySelectorAll('.action-btn.edit').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.currentTarget.dataset.id);
                const task = taskStorage.getAllTasks().find(t => t.id === id);
                if (task) this.openEditModal(task);
            });
        });

        // Botões de deleção
        document.querySelectorAll('.action-btn.delete').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.currentTarget.dataset.id);
                if (confirm('Tem certeza que deseja deletar esta tarefa?')) {
                    taskStorage.deleteTask(id);
                    this.updateStats();
                    this.refreshTasks();
                    this.showToast('Tarefa deletada com sucesso', 'success');
                    this.playSound('delete');
                }
            });
        });

        // Botões de importante
        document.querySelectorAll('.action-btn.important').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.currentTarget.dataset.id);
                const task = taskStorage.getAllTasks().find(t => t.id === id);
                if (task) {
                    taskStorage.updateTask(id, { important: !task.important });
                    this.refreshTasks();
                    this.playSound('click');
                }
            });
        });
    }

    /**
     * Atualiza a lista de tarefas
     */
    refreshTasks() {
        let tasks = taskStorage.getFilteredTasks(this.currentFilter);
        tasks = this.filterByCategory(tasks, this.currentCategory);
        this.renderTasks(tasks);
    }

    /**
     * Filtra tarefas por categoria
     */
    filterByCategory(tasks, category) {
        if (category === 'all') return tasks;
        return tasks.filter(t => t.category === category);
    }
}

