 * MY TASKS - Main Application
 * Lógica principal da aplicação
 */

class TaskApp {
    constructor() {
        this.init();
    }

    /**
     * Inicializa a aplicação
     */
    init() {
        this.loadSettings();
        this.setupEventListeners();
        this.refreshTasks();
        taskUI.updateStats();
    }

    /**
     * Carrega e aplica configurações salvas
     */
    loadSettings() {
        const settings = taskStorage.getSettings();
        if (settings.darkMode) {
            taskUI.toggleDarkMode(true);
        }
    }

    /**
     * Configura todos os listeners de eventos
     */
    setupEventListeners() {
        // Adicionar tarefa
        document.getElementById('addBtn').addEventListener('click', () => this.addTask());
        document.getElementById('taskInput').addEventListener('keypress', (e) => {
            if (e.key === 'Enter') this.addTask();
        });

        // Filtros
        document.querySelectorAll('.filter-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
                e.currentTarget.classList.add('active');
                taskUI.currentFilter = e.currentTarget.dataset.filter;
                this.refreshTasks();
            });
        });

        // Categoria
        document.getElementById('categorySelect').addEventListener('change', (e) => {
            taskUI.currentCategory = e.target.value;
            this.refreshTasks();
        });

        // Modal de edição
        document.getElementById('closeEditModal').addEventListener('click', () => taskUI.closeEditModal());
        document.getElementById('cancelEditBtn').addEventListener('click', () => taskUI.closeEditModal());
        document.getElementById('saveEditBtn').addEventListener('click', () => this.saveEdit());

        // Modal de configurações
        document.getElementById('settingsBtn').addEventListener('click', () => taskUI.openSettingsModal());
        document.getElementById('closeSettingsModal').addEventListener('click', () => taskUI.closeSettingsModal());

        // Limpar concluídas
        document.getElementById('clearCompleted').addEventListener('click', () => this.clearCompleted());

        // Exportar
        document.getElementById('exportBtn').addEventListener('click', () => this.exportTasks());

        // Limpar tudo
        document.getElementById('clearAllBtn').addEventListener('click', () => this.clearAll());

        // Fechar modais ao clicar fora
        document.getElementById('editModal').addEventListener('click', (e) => {
            if (e.target.id === 'editModal') taskUI.closeEditModal();
        });

        document.getElementById('settingsModal').addEventListener('click', (e) => {
            if (e.target.id === 'settingsModal') {
                this.saveSettings();
                taskUI.closeSettingsModal();
            }
        });
    }

    /**
     * Adiciona uma nova tarefa
     */
    addTask() {
        const taskInput = document.getElementById('taskInput');
        const categorySelect = document.getElementById('categorySelect');
        const text = taskInput.value.trim();
        const category = categorySelect.value;

        if (!text) {
            taskUI.showToast('Por favor, digite uma tarefa', 'warning');
            return;
        }

        if (text.length < 3) {
            taskUI.showToast('A tarefa deve ter pelo menos 3 caracteres', 'warning');
            return;
        }

        if (text.length > 100) {
            taskUI.showToast('A tarefa não pode exceder 100 caracteres', 'warning');
            return;
        }

        taskStorage.addTask({ text, category });
        taskInput.value = '';
        categorySelect.value = 'outros';
        this.refreshTasks();
        taskUI.updateStats();
        taskUI.showToast('Tarefa adicionada com sucesso!', 'success');
        taskUI.playSound('complete');
    }

    /**
     * Salva edições de uma tarefa
     */
    saveEdit() {
        if (!taskUI.editingTaskId) return;

        const data = taskUI.getEditModalData();

        if (!data.text.trim()) {
            taskUI.showToast('A descrição não pode estar vazia', 'warning');
            return;
        }

        taskStorage.updateTask(taskUI.editingTaskId, {
            text: data.text,
            category: data.category,
            priority: data.priority
        });

        taskUI.closeEditModal();
        this.refreshTasks();
        taskUI.showToast('Tarefa atualizada com sucesso!', 'success');
        taskUI.playSound('complete');
    }

    /**
     * Limpa tarefas concluídas
     */
    clearCompleted() {
        const stats = taskStorage.getStats();
        if (stats.completed === 0) {
            taskUI.showToast('Nenhuma tarefa concluída para limpar', 'warning');
            return;
        }

        if (confirm(`Tem certeza que deseja deletar ${stats.completed} tarefa(s) concluída(s)?`)) {
            const cleared = taskStorage.clearCompleted();
            this.refreshTasks();
            taskUI.updateStats();
            taskUI.showToast(`${cleared} tarefa(s) deletada(s)`, 'success');
            taskUI.playSound('delete');
        }
    }

    /**
     * Limpa todas as tarefas
     */
    clearAll() {
        const stats = taskStorage.getStats();
        if (stats.total === 0) {
            taskUI.showToast('Nenhuma tarefa para deletar', 'warning');
            return;
        }

        if (confirm(`Tem certeza que deseja deletar TODAS as ${stats.total} tarefa(s)? Esta ação não pode ser desfeita.`)) {
            taskStorage.clearAll();
            this.refreshTasks();
            taskUI.updateStats();
            taskUI.closeSettingsModal();
            taskUI.showToast('Todas as tarefas foram deletadas', 'success');
            taskUI.playSound('delete');
        }
    }

    /**
     * Exporta tarefas como JSON
     */
    exportTasks() {
        const json = taskStorage.exportTasks();
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `tarefas-${new Date().toISOString().split('T')[0]}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        taskUI.showToast('Tarefas exportadas com sucesso!', 'success');
    }

    /**
     * Salva configurações
     */
    saveSettings() {
        const settings = taskUI.getSettingsModalData();
        taskStorage.saveSettings(settings);
        taskUI.toggleDarkMode(settings.darkMode);
        taskUI.showToast('Configurações salvas com sucesso!', 'success');
    }

    /**
     * Atualiza a lista de tarefas
     */
    refreshTasks() {
        taskUI.refreshTasks();
    }
}

// Inicializa a aplicação quando o DOM estiver pronto
document.addEventListener('DOMContentLoaded', () => {
    const app = new TaskApp();
});
