import 'package:uuid/uuid.dart';
import '../models/task.dart';
import '../database/database_helper.dart';

class TaskProvider with ChangeNotifier {
  List<Task> _tasks = [];
  String _filter = 'all';
  String _category = 'all';

  List<Task> get tasks => _filteredTasks;
  String get filter => _filter;
  String get category => _category;

  List<Task> get _filteredTasks {
    List<Task> filtered = _tasks;

    // Aplicar filtro de status
    switch (_filter) {
      case 'completed':
        filtered = filtered.where((t) => t.completed).toList();
        break;
      case 'pending':
        filtered = filtered.where((t) => !t.completed).toList();
        break;
      case 'important':
        filtered = filtered.where((t) => t.important).toList();
        break;
      default:
        break;
    }

    // Aplicar filtro de categoria
    if (_category != 'all') {
      filtered = filtered.where((t) => t.category == _category).toList();
    }

    return filtered;
  }

  Future<void> loadTasks() async {
    _tasks = await DatabaseHelper.instance.getTasks();
    notifyListeners();
  }

  Future<void> addTask(String text, String category, String priority) async {
    final task = Task(
      id: const Uuid().v4(),
      text: text,
      category: category,
      priority: priority,
      createdAt: DateTime.now(),
    );
    await DatabaseHelper.instance.insertTask(task);
    await loadTasks();
  }

  Future<void> updateTask(Task task) async {
    await DatabaseHelper.instance.updateTask(task);
    await loadTasks();
  }

  Future<void> deleteTask(String id) async {
    await DatabaseHelper.instance.deleteTask(id);
    await loadTasks();
  }

  Future<void> toggleTaskCompletion(String id) async {
    final task = _tasks.firstWhere((t) => t.id == id);
    final updated = task.copyWith(completed: !task.completed);
    await updateTask(updated);
  }

  Future<void> toggleTaskImportant(String id) async {
    final task = _tasks.firstWhere((t) => t.id == id);
    final updated = task.copyWith(important: !task.important);
    await updateTask(updated);
  }

  void setFilter(String filter) {
    _filter = filter;
    notifyListeners();
  }

  void setCategory(String category) {
    _category = category;
    notifyListeners();
  }

  Map<String, int> getStats() {
    final total = _tasks.length;
    final completed = _tasks.where((t) => t.completed).length;
    final pending = total - completed;

    return {
      'total': total,
      'completed': completed,
      'pending': pending,
    };
  }

  Future<void> clearCompleted() async {
    final completed = _tasks.where((t) => t.completed).toList();
    for (var task in completed) {
      await DatabaseHelper.instance.deleteTask(task.id);
    }
    await loadTasks();
  }

  Future<void> clearAll() async {
    for (var task in _tasks) {
      await DatabaseHelper.instance.deleteTask(task.id);
    }
    await loadTasks();
  }
}
","path":"flutter-my-tasks/lib/providers/task_provider.dart"},{"content":"import 'package:sqflite/sqflite.dart';
import 'package:path/path.dart';
import '../models/task.dart';

class DatabaseHelper {
  static const _databaseName = 'my_tasks.db';
  static const _databaseVersion = 1;
  static const _tableName = 'tasks';

  DatabaseHelper._privateConstructor();
  static final DatabaseHelper instance = DatabaseHelper._privateConstructor();

  static Database? _database;

  Future<Database> get database async {
    _database ??= await _initDatabase();
    return _database!;
  }

  Future<Database> _initDatabase() async {
    String path = join(await getDatabasesPath(), _databaseName);
    return await openDatabase(
      path,
      version: _databaseVersion,
      onCreate: _onCreate,
    );
  }

  Future<void> _onCreate(Database db, int version) async {
    await db.execute('''
      CREATE TABLE $_tableName (
        id TEXT PRIMARY KEY,
        text TEXT NOT NULL,
        category TEXT NOT NULL,
        priority TEXT NOT NULL,
        completed INTEGER NOT NULL DEFAULT 0,
        important INTEGER NOT NULL DEFAULT 0,
        createdAt TEXT NOT NULL,
        dueDate TEXT
      )
    ''');
  }

  Future<List<Task>> getTasks() async {
    final db = await database;
    final maps = await db.query(_tableName, orderBy: 'createdAt DESC');
    return maps.map((m) => Task.fromMap(m)).toList();
  }

  Future<void> insertTask(Task task) async {
    final db = await database;
    await db.insert(_tableName, task.toMap());
  }

  Future<void> updateTask(Task task) async {
    final db = await database;
    await db.update(
      _tableName,
      task.toMap(),
      where: 'id = ?',
      whereArgs: [task.id],
    );
  }

  Future<void> deleteTask(String id) async {
    final db = await database;
    await db.delete(
      _tableName,
      where: 'id = ?',
      whereArgs: [id],
    );
  }

  Future<void> closeDatabase() async {
    final db = await database;
    db.close();
  }
}
