   WEATHER DASHBOARD - Estilos Principais
   ============================================= */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --primary-color: #1e3a8a;
    --secondary-color: #3b82f6;
    --success-color: #10b981;
    --warning-color: #f59e0b;
    --danger-color: #ef4444;
    --dark-bg: #0f172a;
    --light-bg: #f1f5f9;
    --white: #ffffff;
    --text-dark: #1e293b;
    --text-light: #64748b;
    --border-color: #e2e8f0;
    --shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
    --shadow-lg: 0 10px 15px rgba(0, 0, 0, 0.1);
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: var(--text-dark);
    line-height: 1.6;
    min-height: 100vh;
    transition: background 0.3s ease;
}

body.dark-mode {
    background: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

/* =============================================
   HEADER
   ============================================= */

.header {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 15px;
    padding: 40px 30px;
    margin-bottom: 30px;
    box-shadow: var(--shadow-lg);
    text-align: center;
}

body.dark-mode .header {
    background: rgba(15, 23, 42, 0.95);
}

.app-title {
    font-size: 2.5rem;
    font-weight: 700;
    color: var(--primary-color);
    margin-bottom: 10px;
}

body.dark-mode .app-title {
    color: #60a5fa;
}

.app-subtitle {
    font-size: 1rem;
    color: var(--text-light);
}

/* =============================================
   SEARCH SECTION
   ============================================= */

.search-section {
    background: var(--white);
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 25px;
    box-shadow: var(--shadow);
    position: relative;
}

body.dark-mode .search-section {
    background: #1e293b;
}

.search-wrapper {
    display: flex;
    gap: 10px;
    position: relative;
}

.city-input {
    flex: 1;
    padding: 12px 16px;
    border: 2px solid var(--border-color);
    border-radius: 8px;
    font-size: 1rem;
    transition: all 0.3s ease;
    background: var(--white);
    color: var(--text-dark);
}

body.dark-mode .city-input {
    background: rgba(255, 255, 255, 0.05);
    color: var(--white);
    border-color: #334155;
}

.city-input:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 3px rgba(30, 58, 138, 0.1);
}

.city-input::placeholder {
    color: var(--text-light);
}

body.dark-mode .city-input::placeholder {
    color: #94a3b8;
}

.suggestions {
    position: absolute;
    top: 100%;
    left: 0;
    right: 0;
    background: var(--white);
    border: 1px solid var(--border-color);
    border-top: none;
    border-radius: 0 0 8px 8px;
    max-height: 300px;
    overflow-y: auto;
    z-index: 10;
}

body.dark-mode .suggestions {
    background: #1e293b;
    border-color: #334155;
}

.suggestions.hidden {
    display: none;
}

.suggestion-item {
    padding: 12px 16px;
    cursor: pointer;
    border-bottom: 1px solid var(--border-color);
    transition: background 0.2s;
}

body.dark-mode .suggestion-item {
    border-color: #334155;
}

.suggestion-item:hover {
    background: var(--light-bg);
}

body.dark-mode .suggestion-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

/* =============================================
   BUTTONS
   ============================================= */

.btn {
    padding: 12px 24px;
    border: none;
    border-radius: 8px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    white-space: nowrap;
}

.btn-primary {
    background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
    color: white;
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-lg);
}

.btn-primary:active {
    transform: translateY(0);
}

.btn-secondary {
    background: var(--light-bg);
    color: var(--text-dark);
    border: 1px solid var(--border-color);
}

body.dark-mode .btn-secondary {
    background: #334155;
    color: var(--white);
}

.btn-secondary:hover {
    background: var(--border-color);
}

/* =============================================
   LOADING STATE
   ============================================= */

.loading {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 60px 20px;
    color: var(--white);
    gap: 20px;
}

.loading.hidden {
    display: none;
}

.spinner {
    width: 50px;
    height: 50px;
    border: 4px solid rgba(255, 255, 255, 0.3);
    border-top-color: var(--white);
    border-radius: 50%;
    animation: spin 1s linear infinite;
}

@keyframes spin {
    to {
        transform: rotate(360deg);
    }
}

/* =============================================
   ERROR MESSAGE
   ============================================= */

.error-message {
    background: var(--danger-color);
    color: white;
    padding: 16px;
    border-radius: 8px;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 12px;
}

.error-message.hidden {
    display: none;
}

.error-message i {
    font-size: 1.5rem;
}

/* =============================================
   CURRENT WEATHER SECTION
   ============================================= */

.current-weather-section {
    background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
    border-radius: 15px;
    padding: 30px;
    margin-bottom: 25px;
    box-shadow: var(--shadow-lg);
    color: white;
}

.current-weather-section.hidden {
    display: none;
}

.current-weather {
    display: flex;
    flex-direction: column;
    gap: 25px;
}

.city-info {
    border-bottom: 2px solid rgba(255, 255, 255, 0.2);
    padding-bottom: 15px;
}

.city-name {
    font-size: 2rem;
    margin-bottom: 5px;
}

.current-date {
    font-size: 0.9rem;
    opacity: 0.9;
}

.temperature-section {
    display: flex;
    justify-content: center;
}

.temperature-display {
    display: flex;
    align-items: center;
    gap: 20px;
}

.weather-icon {
    width: 100px;
    height: 100px;
    filter: drop-shadow(0 4px 6px rgba(0, 0, 0, 0.2));
}

.temperature-content {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.temperature {
    font-size: 3.5rem;
    font-weight: 700;
    line-height: 1;
}

.weather-description {
    font-size: 1.2rem;
    opacity: 0.9;
    text-transform: capitalize;
}

.weather-details {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 15px;
}

.detail-item {
    background: rgba(255, 255, 255, 0.15);
    padding: 15px;
    border-radius: 10px;
    display: flex;
    align-items: center;
    gap: 12px;
}

.detail-item i {
    font-size: 1.5rem;
}

.detail-item div {
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.detail-label {
    font-size: 0.85rem;
    opacity: 0.85;
}

.detail-value {
    font-size: 1.1rem;
    font-weight: 600;
}

/* =============================================
   FORECAST SECTIONS
   ============================================= */

.forecast-section {
    background: var(--white);
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 25px;
    box-shadow: var(--shadow);
}

body.dark-mode .forecast-section {
    background: #1e293b;
}

.forecast-section.hidden {
    display: none;
}

.section-title {
    font-size: 1.3rem;
    font-weight: 600;
    color: var(--text-dark);
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 10px;
}

body.dark-mode .section-title {
    color: var(--white);
}

.section-title i {
    color: var(--secondary-color);
}

/* =============================================
   HOURLY FORECAST
   ============================================= */

.hourly-forecast {
    display: grid;
    grid-template-columns: repeat(auto-scroll, minmax(100px, 1fr));
    gap: 12px;
    overflow-x: auto;
    padding: 10px 0;
}

.hourly-item {
    background: var(--light-bg);
    border-radius: 10px;
    padding: 15px;
    text-align: center;
    min-width: 100px;
    border: 1px solid var(--border-color);
    transition: all 0.3s ease;
    display: flex;
    flex-direction: column;
    gap: 10px;
    align-items: center;
}

body.dark-mode .hourly-item {
    background: #334155;
    border-color: #475569;
}

.hourly-item:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow);
