body.dark-mode .daily-header {
    border-color: #475569;
}

.daily-date {
    font-weight: 600;
    color: var(--text-dark);
}

body.dark-mode .daily-date {
    color: var(--white);
}

.daily-icon {
    width: 50px;
    height: 50px;
}

.daily-info {
