    box-shadow: var(--shadow);
}

body.dark-mode .additional-info-section {
    background: #1e293b;
}

.additional-info-section.hidden {
    display: none;
}

.info-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
}

.info-card {
    background: var(--light-bg);
    border-radius: 10px;
    padding: 20px;
    text-align: center;
    border: 1px solid var(--border-color);
    display: flex;
    flex-direction: column;
    gap: 10px;
    transition: all 0.3s ease;
}

body.dark-mode .info-card {
    background: #334155;
    border-color: #475569;
}

.info-card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow);
}

.info-card i {
    font-size: 2rem;
    color: var(--secondary-color);
}

.info-label {
    font-size: 0.9rem;
    color: var(--text-light);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

body.dark-mode .info-label {
    color: #cbd5e1;
}

.info-value {
    font-size: 1.3rem;
    font-weight: 600;
    color: var(--text-dark);
}

body.dark-mode .info-value {
    color: var(--white);
}

/* =============================================
   EMPTY STATE
   ============================================= */

.empty-state {
    text-align: center;
    padding: 80px 30px;
    color: var(--white);
}

.empty-state.hidden {
    display: none;
}

.empty-state i {
    font-size: 4rem;
    margin-bottom: 20px;
    opacity: 0.8;
}

.empty-state h2 {
    font-size: 1.8rem;
    margin-bottom: 10px;
}

.empty-state p {
    font-size: 1rem;
    opacity: 0.9;
}

/* =============================================
   FOOTER
   ============================================= */

.footer {
    margin-top: auto;
    padding-top: 20px;
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    color: var(--white);
    text-align: center;
    font-size: 0.9rem;
}

.footer-content {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.footer a {
    color: inherit;
    text-decoration: none;
    border-bottom: 1px solid rgba(255, 255, 255, 0.5);
}

.footer a:hover {
    border-bottom-color: var(--white);
}

/* =============================================
   TOAST
   ============================================= */

.toast {
    position: fixed;
    bottom: 20px;
    right: 20px;
    background: var(--text-dark);
    color: white;
    padding: 15px 20px;
    border-radius: 8px;
    box-shadow: var(--shadow-lg);
    animation: slideInRight 0.3s ease;
    z-index: 2000;
}

.toast.hidden {
    display: none;
}

.toast.success {
    background: var(--success-color);
}

.toast.error {
    background: var(--danger-color);
}

.toast.warning {
    background: var(--warning-color);
    color: var(--text-dark);
}

@keyframes slideInRight {
    from {
        transform: translateX(400px);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}

/* =============================================
   RESPONSIVE DESIGN
   ============================================= */

@media (max-width: 768px) {
    .container {
        padding: 10px;
    }

    .header {
        padding: 20px 15px;
        margin-bottom: 15px;
    }

    .app-title {
        font-size: 1.8rem;
    }

    .search-wrapper {
        flex-direction: column;
    }

    .search-wrapper .btn {
        width: 100%;
        justify-content: center;
    }

    .temperature {
        font-size: 2.5rem;
    }

    .weather-details {
        grid-template-columns: repeat(2, 1fr);
    }

    .daily-forecast {
        grid-template-columns: 1fr;
    }

    .info-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .toast {
        bottom: 10px;
        right: 10px;
        left: 10px;
    }
}

@media (max-width: 480px) {
    .app-title {
        font-size: 1.5rem;
    }

    .temperature {
        font-size: 2rem;
    }

    .weather-details {
        grid-template-columns: 1fr;
    }

    .detail-item {
        padding: 12px;
    }

    .section-title {
        font-size: 1.1rem;
    }

    .weather-icon {
        width: 80px;
        height: 80px;
    }
}
